# ──────────────────────────────────────────────
# PWA-Icon-Generierung (PNG, einmalig gecacht)
# ──────────────────────────────────────────────
_icon_png_cache: dict[int, bytes] = {}

WORKER_ICON_PRIMARY_RGB = (199, 134, 82)   # #c78652
WORKER_ICON_SECONDARY_RGB = (138, 82, 48)  # #8a5230
WORKER_ICON_TEXT_RGBA = (246, 239, 226, 255)  # #f6efe2


def _generate_icon_png(size: int) -> bytes:
    """Erzeugt ein PNG-Icon (size×size) mit Baupass-Branding."""
    if size in _icon_png_cache:
        return _icon_png_cache[size]

    from PIL import Image, ImageDraw, ImageFont
    import io as _io

    r1, g1, b1 = WORKER_ICON_PRIMARY_RGB
    r2, g2, b2 = WORKER_ICON_SECONDARY_RGB
    radius = max(4, size // 6)
    denom = max(1, 2 * (size - 1))

    try:
        import importlib

        np = importlib.import_module("numpy")
        yi, xi = np.mgrid[0:size, 0:size]
        t = (xi + yi) / denom
        arr = np.zeros((size, size, 4), dtype=np.uint8)
        arr[:, :, 0] = np.clip(r1 + (r2 - r1) * t, 0, 255).astype(np.uint8)
        arr[:, :, 1] = np.clip(g1 + (g2 - g1) * t, 0, 255).astype(np.uint8)
        arr[:, :, 2] = np.clip(b1 + (b2 - b1) * t, 0, 255).astype(np.uint8)
        arr[:, :, 3] = 255
        img_raw = Image.fromarray(arr, "RGBA")
    except ImportError:
        pixels = bytearray(size * size * 4)
        idx = 0
        for y in range(size):
            for x in range(size):
                tn = x + y
                pixels[idx]     = r1 + (r2 - r1) * tn // denom
                pixels[idx + 1] = g1 + (g2 - g1) * tn // denom
                pixels[idx + 2] = b1 + (b2 - b1) * tn // denom
                pixels[idx + 3] = 255
                idx += 4
        img_raw = Image.frombytes("RGBA", (size, size), bytes(pixels))

    mask = Image.new("L", (size, size), 0)
    ImageDraw.Draw(mask).rounded_rectangle([0, 0, size - 1, size - 1], radius=radius, fill=255)
    result = Image.new("RGBA", (size, size), (0, 0, 0, 0))
    result.paste(img_raw, mask=mask)

    draw = ImageDraw.Draw(result)
    text = "BP"
    font_size = max(48, int(size * 0.375))
    font = None
    for fp in ["segoeuib.ttf", "arialbd.ttf", "arial.ttf", "DejaVuSans-Bold.ttf",
               "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
               "/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf"]:
        try:
            font = ImageFont.truetype(fp, font_size)
            break
        except Exception:
            pass
    if font is None:
        font = ImageFont.load_default()

    bbox = draw.textbbox((0, 0), text, font=font)
    tw, th = bbox[2] - bbox[0], bbox[3] - bbox[1]
    text_x = (size - tw) / 2 - bbox[0]
    text_y = size * (330 / 512) - th / 2 - bbox[1]
    draw.text((text_x, text_y), text, fill=WORKER_ICON_TEXT_RGBA, font=font)

    buf = _io.BytesIO()
    result.save(buf, "PNG")
    data = buf.getvalue()
    _icon_png_cache[size] = data
    return data
_default_db_path = BASE_DIR / "backend" / "baupass.db"
# DB path selection:
# 1. Explicit env var BAUPASS_DB_PATH always wins (Render, custom setups).
# 2. Auto-detect Railway persistent volume: if /data exists and is writable,
#    always use /data/baupass.db – even on first deploy (init_db creates it).
#    This ensures data survives redeployments without manual env var config.
# 3. Fall back to backend/baupass.db (local / default).
_explicit_db_path = os.getenv("BAUPASS_DB_PATH", "").strip().replace("\\", "/")
_ephemeral_db_hints = {
    "",
    "backend/baupass.db",
    "/app/backend/baupass.db",
    str(_default_db_path).replace("\\", "/"),
}
_railway_data = Path("/data")
_railway_candidate = _railway_data / "baupass.db"
_railway_volume_ready = _railway_data.is_dir() and os.access(_railway_data, os.W_OK)
_env_db_path = _explicit_db_path

if _railway_volume_ready:
    if _explicit_db_path in _ephemeral_db_hints or not _explicit_db_path.startswith("/data/"):
        if _explicit_db_path and _explicit_db_path not in _ephemeral_db_hints:
            print(
                f"[baupass] WARNING: BAUPASS_DB_PATH={_explicit_db_path} ignored – "
                f"using persistent {_railway_candidate} because /data volume is mounted.",
                flush=True,
            )
        _env_db_path = str(_railway_candidate)
        # Auto-migrate: if the persistent volume is empty but the local fallback DB
        # already has data (companies, workers etc.), copy it over automatically so
        # no data is lost on the first deployment after enabling the volume.
        if not _railway_candidate.exists() and _default_db_path.exists() and _default_db_path.stat().st_size > 0:
            try:
                import shutil as _shutil
                _shutil.copy2(str(_default_db_path), str(_railway_candidate))
                print(f"[baupass] Auto-migrated existing DB from {_default_db_path} to {_railway_candidate}", flush=True)
            except Exception as _migrate_err:
                print(f"[baupass] WARNING: DB auto-migration failed: {_migrate_err}", flush=True)
elif not _env_db_path:
    if (os.getenv("RAILWAY_ENVIRONMENT") or os.getenv("RAILWAY_GIT_COMMIT_SHA") or "").strip():
        if _railway_data.exists():
            print("[baupass] WARNING: /data exists but is not writable – using ephemeral DB.", flush=True)
        else:
            print(
                "[baupass] WARNING: Railway deploy without /data volume – "
                "data will be lost on every redeploy. Mount volume at /data and redeploy.",
                flush=True,
            )

DB_PATH = Path((_env_db_path or str(_default_db_path))).expanduser()
try:
    DB_PATH.parent.mkdir(parents=True, exist_ok=True)
except OSError:
    # Fallback to default if the configured path is not writable (e.g. wrong env var).
    DB_PATH = _default_db_path
    DB_PATH.parent.mkdir(parents=True, exist_ok=True)


def _database_is_persistent(db_path: Path) -> bool:
    """True when SQLite lives on Railway volume (/data) or an explicit persistent path."""
    try:
        resolved = db_path.resolve()
    except OSError:
        resolved = db_path
    resolved_str = str(resolved).replace("\\", "/")
    if resolved_str == "/data/baupass.db" or resolved_str.startswith("/data/"):
        return True
    explicit = os.getenv("BAUPASS_DB_PATH", "").strip().replace("\\", "/")
    return explicit.startswith("/data/")


DB_IS_PERSISTENT = _database_is_persistent(DB_PATH)


def resolve_sqlite_backup_dir() -> Path:
    """Store backups next to the DB on Railway (/data/backups), else under backend/backups."""
    if DB_IS_PERSISTENT:
        backup_dir = Path("/data/backups")
    else:
        backup_dir = BASE_DIR / "backend" / "backups"
    backup_dir.mkdir(parents=True, exist_ok=True)
    return backup_dir


def get_database_runtime_info():
    """DB path, persistence flag, and row counts (for deploy health checks)."""
    try:
        from backend.app.db.runtime import postgres_runtime_enabled
        from backend.app.database import get_database_health

        if postgres_runtime_enabled():
            health = get_database_health()
            workers = companies = 0
            try:
                from backend.app.database import init_postgres_pool, postgres_connection
                from backend.app.db.pg_adapter import PgConnection

                init_postgres_pool()
                with postgres_connection() as raw:
                    db = PgConnection(raw)
                    workers = int(
                        db.execute("SELECT COUNT(*) FROM workers WHERE deleted_at IS NULL").fetchone()[0]
                    )
                    companies = int(
                        db.execute("SELECT COUNT(*) FROM companies WHERE deleted_at IS NULL").fetchone()[0]
                    )
            except Exception as exc:
                return {
                    "backend": "postgres",
                    "persistent": True,
                    "path": os.getenv("DATABASE_URL", "").split("@")[-1][:80],
                    "databaseHealth": health,
                    "countError": str(exc),
                }
            return {
                "backend": "postgres",
                "persistent": True,
                "path": "postgresql",
                "workersActive": workers,
                "companiesActive": companies,
                "databaseHealth": health,
            }
    except ImportError:
        pass

    path = Path(DB_PATH)
    info = {
        "backend": "sqlite",
        "path": str(path),
        "persistent": DB_IS_PERSISTENT,
        "exists": path.exists(),
        "sizeBytes": int(path.stat().st_size) if path.exists() else 0,
        "workersActive": 0,
        "companiesActive": 0,
    }
    if not path.exists():
        return info
    try:
        with closing(sqlite3.connect(str(path), timeout=5)) as db:
            info["workersActive"] = int(
                db.execute("SELECT COUNT(*) FROM workers WHERE deleted_at IS NULL").fetchone()[0]
            )
            info["companiesActive"] = int(
                db.execute("SELECT COUNT(*) FROM companies WHERE deleted_at IS NULL").fetchone()[0]
            )
    except Exception as exc:
        info["countError"] = str(exc)
    return info


