def _init_structured_logging():
    if not _structured_logs_enabled:
        return
    if logger.handlers:
        return
    handler = logging.StreamHandler()
    handler.setFormatter(logging.Formatter("%(message)s"))
    logger.addHandler(handler)
    logger.setLevel(logging.INFO)
    logger.propagate = False


def _coerce_log_value(value):
    if value is None:
        return ""
    if isinstance(value, (str, int, float, bool)):
        return value
    return str(value)


def _sanitize_path_for_log(path_value):
    path_text = (path_value or "")
    if len(path_text) <= _request_log_max_path:
        return path_text
    return f"{path_text[:_request_log_max_path]}..."


def _safe_email_domain(value):
    email_value = str(value or "").strip().lower()
    if "@" not in email_value:
        return ""
    return email_value.rsplit("@", 1)[-1][:80]


def emit_structured_log(event, level=logging.INFO, **fields):
    if not _structured_logs_enabled:
        return
    payload = {
        "ts": datetime.now(timezone.utc).isoformat(),
        "event": event,
    }
    if has_request_context():
        payload["requestId"] = getattr(g, "request_id", "")
        payload["method"] = request.method
        payload["path"] = _sanitize_path_for_log(request.path)
    for key, value in fields.items():
        payload[key] = _coerce_log_value(value)
    try:
        logger.log(level, json.dumps(payload, ensure_ascii=False, separators=(",", ":")))
    except Exception:
        # Logging must never break request handling.
        pass


_init_structured_logging()


def get_cors_origins():
    origins = [
        "http://127.0.0.1:8080",
        "http://localhost:8080",
        "https://saa-s-flow--mahmodscharif12.replit.app",
        re.compile(r"^https://[a-z0-9-]+\.github\.io$"),
        re.compile(r"^https://[a-z0-9-]+\.onrender\.com$"),
        re.compile(r"^https://[a-z0-9-]+\.up\.railway\.app$"),
    ]
    public_base = (os.getenv("PUBLIC_BASE_URL") or os.getenv("BAUPASS_PUBLIC_BASE_URL") or "").strip().rstrip("/")
    if public_base:
        origins.append(public_base)
    extra_origins = [item.strip().rstrip("/") for item in (os.getenv("BAUPASS_CORS_ORIGINS") or "").split(",") if item.strip()]
    return origins + extra_origins

