def row_to_dict(row):
    return dict(row) if row is not None else None


def sanitize_customer_number(raw_value, max_len=12):
    """Lässt alphanumerische Zeichen und Bindestriche durch (Format KU-YY-NNNN)."""
    cleaned = re.sub(r"[^A-Za-z0-9\-]", "", str(raw_value or "")).strip()
    if max_len > 0:
        cleaned = cleaned[:max_len]
    return cleaned


def get_next_customer_number(db):
    """Erzeugt die nächste Kundennummer im Format KU-YY-NNNN, z.B. KU-26-0105."""
    yy = datetime.now().strftime("%y")
    prefix = f"KU-{yy}-"
    row = db.execute(
        "SELECT customer_number FROM companies WHERE customer_number LIKE ? ORDER BY customer_number DESC LIMIT 1",
        (prefix + "%",),
    ).fetchone()
    if row:
        parts = str(row["customer_number"]).split("-")
        if len(parts) == 3 and parts[2].isdigit():
            return f"KU-{yy}-{int(parts[2]) + 1:04d}"
    return f"KU-{yy}-0001"


def create_turnstile_api_key():
    return secrets.token_urlsafe(32)


def hash_turnstile_api_key(raw_key):
    return generate_password_hash(raw_key)


def find_turnstile_by_api_key(db, raw_key):
    if not raw_key:
        return None
    candidates = db.execute(
        "SELECT * FROM users WHERE role = 'turnstile' AND COALESCE(api_key_hash, '') != '' AND COALESCE(is_active, 1) = 1"
    ).fetchall()
    for candidate in candidates:
        if check_password_hash(candidate["api_key_hash"], raw_key):
            return candidate
    return None


def serialize_user(user_row):
    if not user_row:
        return None
    support_read_only = False
    support_company_name = ""
    support_actor_name = ""
    if hasattr(user_row, "keys"):
        keys = set(user_row.keys())
        support_read_only = "support_read_only" in keys and bool(user_row["support_read_only"])
        support_company_name = user_row["support_company_name"] if "support_company_name" in keys and user_row["support_company_name"] else ""
        support_actor_name = user_row["support_actor_name"] if "support_actor_name" in keys and user_row["support_actor_name"] else ""
    preview_company_id = ""
    if hasattr(user_row, "keys") and "preview_company_id" in user_row.keys():
        preview_company_id = user_row["preview_company_id"] or ""
    return {
        "id": user_row["id"],
        "username": user_row["username"],
        "name": user_row["name"],
        "role": user_row["role"],
        "company_id": user_row["company_id"],
        "twofa_enabled": int(user_row["twofa_enabled"]),
        "email": user_row["email"] if hasattr(user_row, "keys") and "email" in set(user_row.keys()) else "",
        "support_read_only": support_read_only,
        "support_company_name": support_company_name,
        "support_actor_name": support_actor_name,
        "preview_company_id": preview_company_id,
    }


def log_audit(event_type, message, target_type=None, target_id=None, company_id=None, actor=None):
    try:
        db = get_db()
        actor_user_id = actor["id"] if actor else None
        actor_role = actor["role"] if actor else None
        resolved_company = company_id if company_id is not None else (actor.get("company_id") if actor else None)
        db.execute(
            """
            INSERT INTO audit_logs (id, event_type, actor_user_id, actor_role, company_id, target_type, target_id, message, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                f"aud-{secrets.token_hex(8)}",
                event_type,
                actor_user_id,
                actor_role,
                resolved_company,
                target_type,
                target_id,
                message,
                now_iso(),
            ),
        )
        db.commit()
    except Exception as exc:
        try:
            from backend.app.db.pg_bootstrap import is_schema_error

            if is_schema_error(exc):
                app.logger.warning("[audit] skipped (schema not ready): %s", exc)
                return
        except ImportError:
            pass
        if "no such table" in str(exc).lower() or "audit_logs" in str(exc).lower():
            app.logger.warning("[audit] skipped: %s", exc)
            return
        raise

    if IMMUTABLE_AUDIT_ENABLED and event_type:
        should_mirror = any(event_type.startswith(prefix) for prefix in IMMUTABLE_AUDIT_EVENT_PREFIXES)
        if should_mirror:
            try:
                from backend.app.audit.immutable import append_immutable_audit_event

                request_id = getattr(g, "request_id", None) if has_request_context() else None
                company_id_int = None
                if resolved_company is not None and str(resolved_company).strip().isdigit():
                    company_id_int = int(resolved_company)
                append_immutable_audit_event(
                    db,
                    event_type=event_type,
                    payload={
                        "message": message,
                        "targetType": target_type,
                        "targetId": target_id,
                    },
                    company_id=company_id_int,
                    actor_id=actor_user_id,
                    request_id=request_id,
                    source="legacy_audit",
                )
                db.commit()
            except Exception as exc:
                app.logger.warning(f"[audit] immutable mirror failed for {event_type}: {exc}")


def is_read_only_support_session(session_row):
    if not session_row:
        return False
    if hasattr(session_row, "keys") and "support_read_only" in session_row.keys():
        return bool(session_row["support_read_only"])
    return False


def is_read_only_support_request_allowed():
    if request.method in {"GET", "HEAD", "OPTIONS"}:
        return True
    return request.path in {"/api/logout", "/api/me/heartbeat"}


def is_tenant_host_valid(db, user):
    if not user or user.get("role") == "superadmin":
        return True
    setting = db.execute("SELECT enforce_tenant_domain FROM settings WHERE id = 1").fetchone()
    if not setting or int(setting["enforce_tenant_domain"]) != 1:
        return True
    company_id = user.get("company_id")
    if not company_id:
        return True
    company = db.execute("SELECT access_host FROM companies WHERE id = ?", (company_id,)).fetchone()
    required_host = (company["access_host"] if company else "").strip().lower()
    if not required_host:
        return True
    return get_request_host() == required_host


def require_auth(handler):
    @wraps(handler)
    def wrapper(*args, **kwargs):
        token = get_auth_token_from_request()
        if not token:
            return jsonify({"error": "unauthorized"}), 401
        db = get_db()
        session = db.execute(
            "SELECT user_id, expires_at, support_read_only, support_company_name, support_actor_name, preview_company_id FROM sessions WHERE token = ?",
            (token,),
        ).fetchone()
        if not session:
            return jsonify({"error": "invalid_session"}), 401

        if session["expires_at"] < now_iso():
            db.execute("DELETE FROM sessions WHERE token = ?", (token,))
            db.commit()
            return jsonify({"error": "session_expired"}), 401

        user = db.execute("SELECT * FROM users WHERE id = ?", (session["user_id"],)).fetchone()
        if not user:
            return jsonify({"error": "invalid_user"}), 401

        if int(user["is_active"] if "is_active" in user.keys() else 1) == 0:
            return jsonify({"error": "account_disabled"}), 403

        user_payload = row_to_dict(user)
        user_payload["support_read_only"] = is_read_only_support_session(session)
        user_payload["support_company_name"] = session["support_company_name"] or ""
        user_payload["support_actor_name"] = session["support_actor_name"] or ""
        user_payload["preview_company_id"] = session["preview_company_id"] or ""

        if not is_tenant_host_valid(db, user_payload):
            return jsonify({"error": "forbidden_tenant_host"}), 403

        if user_payload.get("role") != "superadmin":
            company_error = get_company_access_error(db, user_payload.get("company_id"))
            if company_error:
                db.execute("DELETE FROM sessions WHERE token = ?", (token,))
                db.commit()
                return jsonify(company_error), 403

        if user_payload.get("role") in ["superadmin", "company-admin"]:
            settings_row = db.execute("SELECT admin_ip_whitelist FROM settings WHERE id = 1").fetchone()
            whitelist = parse_ip_whitelist(settings_row["admin_ip_whitelist"] if settings_row else "")
            if whitelist and not ip_allowed(get_client_ip(), whitelist):
                return jsonify({"error": "admin_ip_not_allowed"}), 403

        if is_read_only_support_session(session) and not is_read_only_support_request_allowed():
            return jsonify({"error": "support_session_read_only"}), 403

        try:
            from backend.app.platform.security.session_devices import session_device_allowed, touch_session_device

            allowed, device_reason = session_device_allowed(db, token=token, req=request)
            if not allowed:
                return jsonify({"error": device_reason or "device_denied"}), 403
            touch_session_device(db, token=token)
        except Exception:
            pass

        db.execute("UPDATE sessions SET expires_at = ? WHERE token = ?", (expiry_iso(), token))
        db.commit()

        g.current_user = user_payload
        g.token = token
        g.current_session = row_to_dict(session)
        g.preview_company_id = user_payload["preview_company_id"] if user_payload.get("role") == "superadmin" else ""
        return handler(*args, **kwargs)

    return wrapper


def require_roles(*roles):
    def decorator(handler):
        @wraps(handler)
        def wrapper(*args, **kwargs):
            user = g.current_user
            if user["role"] not in roles:
                return jsonify({"error": "forbidden"}), 403
            return handler(*args, **kwargs)

        return wrapper

    return decorator


def require_admin_session(handler):
    """Decorator to require admin/user session with company context."""
    @wraps(handler)
    def wrapper(*args, **kwargs):
        # Get Authorization header or cookie
        auth_header = request.headers.get("Authorization", "").strip()
        token = None
        
        if auth_header.startswith("Bearer "):
            token = auth_header[7:]
        
        if not token:
            return jsonify({"error": "unauthorized"}), 401
        
        # For now, accept any non-empty token (admin endpoints in existing code use session context)
        # In production, validate token against actual admin sessions
        db = get_db()
        
        # Set g.admin_user and g.admin_token for handler access
        g.admin_user = {
            "id": "admin-" + secrets.token_hex(8),
            "company_id": request.args.get("company_id", "default-company"),
            "role": "company-admin"
        }
        g.admin_token = token
        
        return handler(*args, **kwargs)
    
    return wrapper


def require_worker_session(handler):
    @wraps(handler)
    def wrapper(*args, **kwargs):
        def _rate_limited_response(retry_after, scope="worker_api", audit_on_limit=False):
            retry_seconds = max(1, int(retry_after or 1))
            if audit_on_limit:
                try:
                    client_ip = get_client_ip()
                    user_agent = str(request.headers.get("User-Agent") or "").strip()
                    user_agent = re.sub(r"\s+", " ", user_agent).replace("|", "/").strip()
                    if len(user_agent) > 120:
                        user_agent = user_agent[:120]
                    now_ts = time.time()
                    dedup_bucket = int(now_ts // WORKER_RATE_LIMIT_AUDIT_DEDUP_SECONDS)
                    audit_key = f"{scope}|{client_ip}|{dedup_bucket}"
                    should_log_audit = False
                    with _rate_lock:
                        if not _worker_rate_limit_audit_state.get(audit_key):
                            _worker_rate_limit_audit_state[audit_key] = now_ts
                            should_log_audit = True
                        # Keep only recent buckets to avoid unbounded memory growth.
                        cutoff_ts = now_ts - WORKER_RATE_LIMIT_AUDIT_DEDUP_SECONDS
                        stale_keys = [
                            key for key, ts in _worker_rate_limit_audit_state.items() if not isinstance(ts, (int, float)) or ts < cutoff_ts
                        ]
                        for stale_key in stale_keys:
                            _worker_rate_limit_audit_state.pop(stale_key, None)
                    if should_log_audit:
                        log_audit(
                            "worker.session.rate_limited",
                            f"Worker session request limited (scope={scope}, ip={client_ip}, method={request.method}, status=429, retry_after={retry_seconds}s, path={request.path}, ua={user_agent})",
                            target_type="worker-session",
                        )
                except Exception:
                    pass
            response = jsonify(
                {
                    "error": "rate_limited",
                    "message": "Too many requests. Please retry later.",
                    "retryAfterSeconds": retry_seconds,
                }
            )
            response.headers["Retry-After"] = str(retry_seconds)
            return response, 429

        allowed, retry_after = check_rate_limit("worker_api")
        if not allowed:
            return _rate_limited_response(retry_after)

        def _worker_auth_fail(error_code, message):
            fail_allowed, fail_retry_after = check_rate_limit("worker_api_auth_fail")
            if not fail_allowed:
                return _rate_limited_response(fail_retry_after, scope="worker_api_auth_fail", audit_on_limit=True)
            return jsonify({"error": error_code, "message": message}), 401

        auth_header = str(request.headers.get("Authorization", "") or "").strip()
        if not auth_header:
            return _worker_auth_fail("unauthorized", "Missing bearer token.")

        parts = auth_header.split(None, 1)
        if len(parts) != 2 or parts[0].lower() != "bearer":
            return _worker_auth_fail("unauthorized", "Authorization scheme must be Bearer.")

        token = parts[1].strip()
        if not token:
            return _worker_auth_fail("unauthorized", "Bearer token is empty.")
        if len(token) > 2048:
            return _worker_auth_fail("unauthorized", "Bearer token is too long.")

        session_token, jwt_claims = resolve_worker_session_token_from_bearer(token)
        if not session_token:
            return _worker_auth_fail("invalid_worker_session", "Session token is invalid or expired.")

        db = get_db()
        purged = _throttled_session_purge(db)
        if purged > 0:
            db.commit()
        session = db.execute(
            "SELECT worker_id, expires_at, bound_device_id FROM worker_app_sessions WHERE token = ?",
            (session_token,),
        ).fetchone()
        if not session:
            return _worker_auth_fail(
                "invalid_worker_session",
                "Sitzung nicht gefunden. Bitte mit Badge-ID und PIN erneut anmelden.",
            )

        now_value = now_iso()
        if session["expires_at"] < now_value:
            db.execute("DELETE FROM worker_app_sessions WHERE token = ?", (session_token,))
            db.commit()
            return _worker_auth_fail("worker_session_expired", "Session has expired.")

        worker = db.execute("SELECT * FROM workers WHERE id = ?", (session["worker_id"],)).fetchone()
        if not worker or worker["deleted_at"]:
            return _worker_auth_fail("worker_not_available", "Worker record no longer available.")

        company_error = get_company_access_error(db, worker["company_id"])
        if company_error:
            db.execute("DELETE FROM worker_app_sessions WHERE token = ?", (session_token,))
            db.commit()
            return jsonify(company_error), 403

        plan_value = get_company_plan(db, worker["company_id"])
        if not company_has_feature(plan_value, "worker_app"):
            db.execute("DELETE FROM worker_app_sessions WHERE token = ?", (session_token,))
            db.commit()
            return feature_not_available_response("worker_app", plan_value)

        device_error = validate_worker_bound_device_or_raise(db, worker["id"], session_token)
        if device_error:
            return device_error

        refreshed_expires_at = resolve_worker_session_expiry_iso(worker)
        if refreshed_expires_at != session["expires_at"]:
            db.execute(
                "UPDATE worker_app_sessions SET expires_at = ? WHERE token = ?",
                (refreshed_expires_at, session_token),
            )
            db.commit()

        g.worker = row_to_dict(worker)
        g.worker_token = session_token
        g.worker_bearer_token = token
        g.worker_jwt_claims = jwt_claims
        g.worker_bound_device_id = str(session["bound_device_id"] or "").strip()
        g.worker_session_expires_at = refreshed_expires_at
        return handler(*args, **kwargs)

    return wrapper


