@app.get("/api/session/bootstrap")
def session_bootstrap():
    from backend.app.db.schema_errors import guard_core_schema

    blocked = guard_core_schema()
    if blocked is not None:
        return blocked

    token = get_auth_token_from_request()
    if not token:
        return jsonify({"authenticated": False, "error": "unauthorized"})

    user = get_user_from_session_token(token)
    if not user:
        return jsonify({"authenticated": False, "error": "unauthorized"})

    try:
        db = get_db()
    except Exception as exc:
        try:
            from backend.app.db.pg_bootstrap import is_schema_error
            from backend.app.db.schema_errors import database_not_ready_response

            if is_schema_error(exc):
                return database_not_ready_response()
        except ImportError:
            pass
        raise
    if not is_tenant_host_valid(db, user):
        return jsonify({"error": "forbidden_tenant_host"}), 403

    if user.get("role") != "superadmin":
        company_error = get_company_access_error(db, user.get("company_id"))
        if company_error:
            db.execute("DELETE FROM sessions WHERE token = ?", (token,))
            db.commit()
            return jsonify(company_error), 403

    try:
        if user.get("role") in ["superadmin", "company-admin"]:
            settings_row = db.execute("SELECT admin_ip_whitelist FROM settings WHERE id = 1").fetchone()
            whitelist = parse_ip_whitelist(settings_row["admin_ip_whitelist"] if settings_row else "")
            if whitelist and not ip_allowed(get_client_ip(), whitelist):
                return jsonify({"error": "admin_ip_not_allowed"}), 403

        db.execute("UPDATE sessions SET expires_at = ? WHERE token = ?", (expiry_iso(), token))
        db.commit()
    except Exception as exc:
        try:
            from backend.app.db.pg_bootstrap import is_schema_error
            from backend.app.db.schema_errors import database_not_ready_response

            if is_schema_error(exc):
                return database_not_ready_response()
        except ImportError:
            pass
        raise

    return jsonify({"authenticated": True, "token": token, "user": serialize_user(user)})


@app.get("/api/system/status")
@require_auth
@require_roles("superadmin")
def system_status():
    db = get_db()
    active_sessions = db.execute("SELECT COUNT(*) AS c FROM sessions WHERE expires_at >= ?", (now_iso(),)).fetchone()["c"]
    worker_sessions = db.execute("SELECT COUNT(*) AS c FROM worker_app_sessions WHERE expires_at >= ?", (now_iso(),)).fetchone()["c"]
    open_entries = db.execute(
        """
        SELECT COUNT(*) AS c
        FROM (
            SELECT access_logs.worker_id, MAX(access_logs.timestamp) AS latest_ts
            FROM access_logs
            JOIN workers ON workers.id = access_logs.worker_id
            WHERE workers.deleted_at IS NULL
            GROUP BY access_logs.worker_id
        ) latest
        JOIN access_logs ON access_logs.worker_id = latest.worker_id AND access_logs.timestamp = latest.latest_ts
        WHERE access_logs.direction = 'check-in'
        """
    ).fetchone()["c"]

    recent_issues = db.execute(
        """
        SELECT event_type, message, created_at
        FROM audit_logs
        WHERE event_type IN ('login.failed', 'security.password_changed', 'access.booked')
           OR event_type LIKE 'company.%'
           OR event_type LIKE 'worker.%'
        ORDER BY created_at DESC
        LIMIT 20
        """
    ).fetchall()

    locks = []
    now = utc_now()
    for key, state in list(failed_login_attempts.items()):
        locked_until = state.get("locked_until")
        if not locked_until:
            continue
        if locked_until <= now:
            failed_login_attempts.pop(key, None)
            continue
        locks.append(
            {
                "key": key,
                "retryAfterSeconds": int((locked_until - now).total_seconds()),
            }
        )

    session_details = db.execute(
        """
        SELECT s.last_seen, u.name, u.role, u.username
        FROM sessions s
        JOIN users u ON u.id = s.user_id
        WHERE s.expires_at >= ?
        ORDER BY s.last_seen DESC
        LIMIT 20
        """,
        (now_iso(),),
    ).fetchall()

    setting = db.execute(
        "SELECT worker_app_enabled, smtp_host, smtp_sender_email, platform_name FROM settings WHERE id = 1"
    ).fetchone()
    diagnostics = get_runtime_diagnostics()
    wallet_status = _wallet_collect_runtime_status()
    backup_dir = resolve_sqlite_backup_dir()
    db_backup_count = len(list(backup_dir.glob("db-backup-*.db")))
    redis_ready = False
    try:
        from backend.app.tasks import task_queues_ready

        redis_ready = bool(task_queues_ready())
    except Exception:
        redis_ready = False

    public_base = get_public_base_url()
    worker_build = _get_worker_build_info().get("build") or "latest"
    worker_install_url = f"{public_base}/worker-install.html?v={worker_build}"

    smtp_host_value = str((setting["smtp_host"] if setting else "") or "").strip()
    smtp_configured = bool(smtp_host_value) or bool(diagnostics.get("brevoConfigured")) or bool(diagnostics.get("resendConfigured"))

    return jsonify(
        {
            "serverTime": now_iso(),
            "currentHost": get_request_host(),
            "currentIp": get_client_ip(),
            "activeSessions": active_sessions,
            "activeWorkerSessions": worker_sessions,
            "openEntries": open_entries,
            "loginLocks": locks[:50],
            "recentIssues": [row_to_dict(row) for row in recent_issues],
            "sessionDetails": [
                {
                    "name": row["name"],
                    "role": row["role"],
                    "username": row["username"],
                    "lastSeen": row["last_seen"],
                }
                for row in session_details
            ],
            "workerAppEnabled": int(setting["worker_app_enabled"]) == 1 if setting else True,
            "publicBaseUrl": public_base,
            "workerInstallUrl": worker_install_url,
            "smtpConfigured": smtp_configured,
            "redisReady": redis_ready,
            "dbBackupCount": db_backup_count,
            "database": get_database_runtime_info(),
            "databaseBackupDir": str(backup_dir),
            "wallet": wallet_status,
            "runtimeWarnings": diagnostics.get("warnings") or [],
        }
    )


