def build_worker_app_access_payload(db, worker_id, actor_user):
    worker = db.execute("SELECT * FROM workers WHERE id = ?", (worker_id,)).fetchone()
    if not worker:
        return None, (jsonify({"error": "worker_not_found"}), 404)

    if actor_user["role"] != "superadmin" and worker["company_id"] != actor_user.get("company_id"):
        return None, (jsonify({"error": "forbidden_worker"}), 403)

    if worker["deleted_at"]:
        return None, (jsonify({"error": "worker_deleted"}), 400)

    if worker_visit_has_expired(worker):
        return None, (jsonify({"error": "visitor_visit_expired", "message": "Diese Besucherkarte ist zeitlich abgelaufen."}), 400)

    now = now_iso()
    db.execute(
        "UPDATE worker_app_tokens SET revoked_at = ? WHERE worker_id = ? AND revoked_at IS NULL AND expires_at >= ?",
        (now, worker_id, now),
    )

    access_token = secrets.token_urlsafe(32)
    access_expires_at = resolve_worker_access_token_expiry_iso(worker)
    db.execute(
        "INSERT INTO worker_app_tokens (token, worker_id, expires_at, revoked_at, created_by_user_id) VALUES (?, ?, ?, NULL, ?)",
        (access_token, worker_id, access_expires_at, actor_user["id"]),
    )
    db.commit()

    build_tag = _get_worker_build_info().get("build") or "latest"
    public_base = get_public_base_url().rstrip("/")
    api_base_param = urlencode({"apiBase": public_base}) if public_base else ""
    join_query = f"access={access_token}&v={build_tag}&launch=1"
    if api_base_param:
        join_query = f"{join_query}&{api_base_param}"
    link = f"{public_base}/join.html?{join_query}"
    pwa_link = f"{public_base}/worker-install.html?access={access_token}&v={build_tag}"
    if api_base_param:
        pwa_link = f"{pwa_link}&{api_base_param}"
    return {
        "accessToken": access_token,
        "link": link,
        "joinLink": link,
        "pwaLink": pwa_link,
        "deepLink": f"baupass://join?access={access_token}",
        "created": True,
        "oneTime": True,
        "accessExpiresAt": access_expires_at,
        "workerId": worker_id,
    }, None


def normalize_company_access_mode(value):
    mode = str(value or "gate").strip().lower()
    return "site_app" if mode in {"site_app", "site-app", "industry", "industrie", "standort"} else "gate"


def normalize_site_geofence_radius_meters(value, access_mode="gate"):
    if normalize_company_access_mode(access_mode) == "site_app":
        try:
            radius = int(value)
        except (TypeError, ValueError):
            radius = WORKER_SITE_GEOFENCE_DEFAULT_METERS
        return max(WORKER_SITE_GEOFENCE_MIN_METERS, min(WORKER_SITE_GEOFENCE_MAX_METERS, radius))
    return WORKER_LOGIN_MAX_DISTANCE_METERS


def get_company_site_access_row(db, company_id):
    if not company_id:
        return None
    return db.execute(
        """
        SELECT access_mode, site_geofence_radius_meters, site_auto_checkin, site_auto_logout_on_leave,
               work_start_time, work_end_time
        FROM companies
        WHERE id = ? AND deleted_at IS NULL
        LIMIT 1
        """,
        (company_id,),
    ).fetchone()


def get_company_site_access_config(db, company_id):
    row = get_company_site_access_row(db, company_id)
    access_mode = normalize_company_access_mode(row["access_mode"] if row else "gate")
    radius = normalize_site_geofence_radius_meters(
        row["site_geofence_radius_meters"] if row else WORKER_SITE_GEOFENCE_DEFAULT_METERS,
        access_mode,
    )
    return {
        "accessMode": access_mode,
        "siteGeofenceRadiusMeters": radius,
        "siteAutoCheckin": bool(int(row["site_auto_checkin"])) if row and "site_auto_checkin" in row.keys() else True,
        "siteAutoLogoutOnLeave": bool(int(row["site_auto_logout_on_leave"])) if row and "site_auto_logout_on_leave" in row.keys() else True,
        "workStartTime": str(row["work_start_time"] or "").strip() if row else "",
        "workEndTime": str(row["work_end_time"] or "").strip() if row else "",
    }


def is_company_workday_today():
    # Mo–Fr = Arbeitstag (Industrie-Standard)
    return datetime.now().weekday() < 5


def worker_has_open_checkin_today(db, worker_id):
    today_prefix = datetime.now().strftime("%Y-%m-%d")
    open_row = db.execute(
        """
        SELECT al.id
        FROM access_logs al
        WHERE al.worker_id = ?
          AND al.timestamp LIKE ?
          AND al.direction = 'check-in'
          AND NOT EXISTS (
              SELECT 1 FROM access_logs al2
              WHERE al2.worker_id = al.worker_id
                AND al2.timestamp > al.timestamp
                AND al2.timestamp LIKE ?
                AND al2.direction = 'check-out'
          )
        ORDER BY al.timestamp DESC
        LIMIT 1
        """,
        (worker_id, f"{today_prefix}%", f"{today_prefix}%"),
    ).fetchone()
    return bool(open_row)


def get_effective_work_end_time(db, worker_id):
    row = db.execute(
        """
        SELECT c.work_end_time AS company_work_end_time, s.work_end_time AS global_work_end_time
        FROM workers w
        LEFT JOIN companies c ON c.id = w.company_id
        LEFT JOIN settings s ON s.id = 1
        WHERE w.id = ?
        LIMIT 1
        """,
        (worker_id,),
    ).fetchone()
    if not row:
        return ""
    return str(row["company_work_end_time"] or row["global_work_end_time"] or "").strip()


def measure_worker_site_distance(db, worker, location):
    if normalize_worker_type(worker["worker_type"]) != "worker":
        return None
    site_coordinates = ensure_worker_site_coordinates(db, worker)
    if not site_coordinates:
        return None
    if not isinstance(location, dict):
        raise ValueError("worker_geolocation_required")
    device_latitude = _normalize_float(location.get("latitude"))
    device_longitude = _normalize_float(location.get("longitude"))
    if device_latitude is None or device_longitude is None:
        raise ValueError("worker_geolocation_required")
    distance_meters = _haversine_meters(
        site_coordinates[0], site_coordinates[1], device_latitude, device_longitude
    )
    return {
        "distanceMeters": int(round(distance_meters)),
        "siteLatitude": float(site_coordinates[0]),
        "siteLongitude": float(site_coordinates[1]),
        "deviceLatitude": float(device_latitude),
        "deviceLongitude": float(device_longitude),
    }


def maybe_site_app_auto_checkin(db, worker):
    company_id = worker["company_id"]
    site_cfg = get_company_site_access_config(db, company_id)
    if site_cfg["accessMode"] != "site_app" or not site_cfg["siteAutoCheckin"]:
        return None
    if not is_company_workday_today():
        return None
    if worker_has_open_checkin_today(db, worker["id"]):
        return None
    log_id = create_access_log_entry(
        db,
        worker["id"],
        "check-in",
        "Mitarbeiter-App (Standort)",
        "Automatischer Check-in nach Standort-Login",
        worker_type=worker["worker_type"],
    )
    return log_id


def serialize_worker_for_app(worker, db=None, company_id=None):
    site_location = None
    latitude = worker["site_latitude"] if hasattr(worker, "keys") and "site_latitude" in worker.keys() else None
    longitude = worker["site_longitude"] if hasattr(worker, "keys") and "site_longitude" in worker.keys() else None
    radius_meters = WORKER_LOGIN_MAX_DISTANCE_METERS
    if db is not None:
        cid = company_id or worker["company_id"]
        radius_meters = get_company_site_access_config(db, cid)["siteGeofenceRadiusMeters"]
    if latitude is not None and longitude is not None:
        site_location = {
            "latitude": float(latitude),
            "longitude": float(longitude),
            "radiusMeters": radius_meters,
        }
    return {
        "id": worker["id"],
        "subcompanyId": worker["subcompany_id"],
        "firstName": worker["first_name"],
        "lastName": worker["last_name"],
        "workerType": normalize_worker_type(worker["worker_type"]),
        "role": worker["role"],
        "site": worker["site"],
        "validUntil": worker["valid_until"],
        "visitorCompany": worker["visitor_company"],
        "visitPurpose": worker["visit_purpose"],
        "hostName": worker["host_name"],
        "visitEndAt": worker["visit_end_at"],
        "status": worker["status"],
        "photoData": worker["photo_data"],
        "badgeId": worker["badge_id"],
        "siteLocation": site_location,
        "leaveBalance": int(worker["leave_balance"]) if (hasattr(worker, "keys") and "leave_balance" in worker.keys() and worker["leave_balance"] is not None) else 30,
    }


def _normalize_float(value):
    if value is None or value == "":
        return None
    try:
        return float(value)
    except (TypeError, ValueError):
        return None


def _haversine_meters(latitude_a, longitude_a, latitude_b, longitude_b):
    earth_radius_m = 6371000.0
    lat1 = math.radians(float(latitude_a))
    lon1 = math.radians(float(longitude_a))
    lat2 = math.radians(float(latitude_b))
    lon2 = math.radians(float(longitude_b))
    dlat = lat2 - lat1
    dlon = lon2 - lon1
    haversine = math.sin(dlat / 2) ** 2 + math.cos(lat1) * math.cos(lat2) * math.sin(dlon / 2) ** 2
    return 2 * earth_radius_m * math.asin(math.sqrt(haversine))


def _geocode_site_address(site_label):
    normalized = str(site_label or "").strip()
    if not normalized:
        return None
    cache_key = normalized.lower()
    if cache_key in _site_geocode_cache:
        return _site_geocode_cache[cache_key]

    encoded_query = quote(normalized)
    geocode_url = f"https://nominatim.openstreetmap.org/search?q={encoded_query}&format=jsonv2&limit=1"
    request_obj = Request(
        geocode_url,
        headers={
            "User-Agent": "BauPass Control/1.0 (worker geofence)",
            "Accept": "application/json",
        },
    )
    try:
        with urlopen(request_obj, timeout=4) as response:
            payload = json.loads(response.read().decode("utf-8"))
    except (URLError, HTTPError, TimeoutError, json.JSONDecodeError, OSError):
        _site_geocode_cache[cache_key] = None
        return None

    if not payload:
        _site_geocode_cache[cache_key] = None
        return None

    first_hit = payload[0]
    latitude = _normalize_float(first_hit.get("lat"))
    longitude = _normalize_float(first_hit.get("lon"))
    if latitude is None or longitude is None:
        _site_geocode_cache[cache_key] = None
        return None

    _site_geocode_cache[cache_key] = (latitude, longitude)
    return _site_geocode_cache[cache_key]


def ensure_worker_site_coordinates(db, worker):
    latitude = worker["site_latitude"] if hasattr(worker, "keys") and "site_latitude" in worker.keys() else None
    longitude = worker["site_longitude"] if hasattr(worker, "keys") and "site_longitude" in worker.keys() else None
    if latitude is not None and longitude is not None:
        return float(latitude), float(longitude)

    geocoded = _geocode_site_address(worker["site"])
    if not geocoded:
        return None

    latitude, longitude = geocoded
    db.execute(
        "UPDATE workers SET site_latitude = ?, site_longitude = ? WHERE id = ?",
        (latitude, longitude, worker["id"]),
    )
    db.commit()
    return latitude, longitude


def validate_worker_login_distance_or_raise(db, worker, payload):
    if normalize_worker_type(worker["worker_type"]) != "worker":
        return None

    site_coordinates = ensure_worker_site_coordinates(db, worker)
    if not site_coordinates:
        return None

    location = payload.get("location") if isinstance(payload, dict) else None
    measured = measure_worker_site_distance(db, worker, location)
    if not measured:
        return None

    site_cfg = get_company_site_access_config(db, worker["company_id"])
    max_distance = int(site_cfg["siteGeofenceRadiusMeters"])
    if measured["distanceMeters"] > max_distance:
        raise PermissionError(f"outside_site_radius:{measured['distanceMeters']}")

    measured["radiusMeters"] = max_distance
    measured["accessMode"] = site_cfg["accessMode"]
    return measured


def normalize_badge_id(value):
    normalized = str(value or "").strip().upper()
    # Normalize unicode dash variants and remove all whitespace inside the ID.
    normalized = re.sub(r"[\u2010\u2011\u2012\u2013\u2014\u2015\u2212]", "-", normalized)
    normalized = re.sub(r"\s+", "", normalized)
    return normalized


def normalize_badge_pin(value):
    return re.sub(r"\s+", "", str(value or "").strip())


def validate_badge_pin_or_raise(pin_value):
    normalized_pin = normalize_badge_pin(pin_value)
    if not re.fullmatch(r"\d{4,8}", normalized_pin):
        raise ValueError("invalid_badge_pin")
    return normalized_pin


def normalize_physical_card_id(value):
    normalized = str(value or "").strip().upper()
    return normalized or None


def normalize_nfc_uid(value):
    """Normalize NFC tag UID for comparison (hex only, uppercase)."""
    base = normalize_physical_card_id(value)
    if not base:
        return None
    compact = re.sub(r"[^0-9A-F]", "", base)
    return compact or None


def normalize_device_protocol(value):
    normalized = str(value or "").strip().lower()
    if normalized in {"usb", "http", "tcp", "mqtt", "serial"}:
        return normalized
    return "http"


# ─────────────────────────────────────────────────────────────────────────────
# Reader Adapter Layer  (Enterprise Point 4)
# Each adapter normalises a raw device payload into a standard BauPass event.
# New reader brands can be supported by adding a new subclass.
# ─────────────────────────────────────────────────────────────────────────────

class BaseReaderAdapter:
    """Base class for hardware reader payload normalisation."""
    reader_type = "generic"

    def normalize(self, raw_payload: dict, context: dict | None = None) -> dict:
        """Return a normalised event dict.  context may carry device_id / company_id
        resolved from auth headers when they are absent in the payload itself."""
        ctx = context or {}
        return {
            "employee_id": str(raw_payload.get("employee_id") or raw_payload.get("badge_id") or ""),
            "device_id":   str(raw_payload.get("device_id")   or raw_payload.get("deviceId") or ctx.get("device_id", "")),
            "timestamp":   str(raw_payload.get("timestamp")   or ""),
            "event":       "check_in" if str(raw_payload.get("event") or raw_payload.get("direction", "check_in")).lower() in {"check_in", "check-in", "in", "entry"} else "check_out",
            "source":      normalize_scan_source(raw_payload.get("source")),
            "protocol":    normalize_device_protocol(raw_payload.get("protocol")),
        }

    @classmethod
    def detect(cls, raw_payload: dict) -> bool:
        """Return True when this adapter is the best match for the payload."""
        return False


class ZKTecoAdapter(BaseReaderAdapter):
    """ZKTeco push SDK payload (PUSH protocol / ADMS)."""
    reader_type = "zkteco"

    _DIRECTION_MAP = {"0": "check_in", "in": "check_in", "1": "check_out", "out": "check_out", "2": "check_out", "4": "check_in"}

    def normalize(self, raw_payload: dict, context: dict | None = None) -> dict:
        ctx = context or {}
        raw_dir = str(raw_payload.get("InOutStatus") or raw_payload.get("inOutStatus") or "0").lower()
        event = self._DIRECTION_MAP.get(raw_dir, "check_in")
        return {
            "employee_id": str(raw_payload.get("Pin") or raw_payload.get("pin") or ""),
            "device_id":   str(raw_payload.get("DevSN") or raw_payload.get("devSN") or ctx.get("device_id", "")),
            "timestamp":   str(raw_payload.get("LogTime") or raw_payload.get("logTime") or ""),
            "event":       event,
            "source":      "rfid",
            "protocol":    "zkteco_push",
        }

    @classmethod
    def detect(cls, raw_payload: dict) -> bool:
        return ("Pin" in raw_payload or "pin" in raw_payload) and ("DevSN" in raw_payload or "devSN" in raw_payload)


class ACSAdapter(BaseReaderAdapter):
    """ACS / Lenel / generic access-control-system payload."""
    reader_type = "acs"

    def normalize(self, raw_payload: dict, context: dict | None = None) -> dict:
        ctx = context or {}
        raw_dir = str(raw_payload.get("direction") or raw_payload.get("event_type") or "in").lower()
        event = "check_in" if raw_dir in {"in", "entry", "check_in", "check-in", "access_granted"} else "check_out"
        return {
            "employee_id": str(raw_payload.get("card_holder_id") or raw_payload.get("badge") or raw_payload.get("cardholderID") or ""),
            "device_id":   str(raw_payload.get("reader_id") or raw_payload.get("readerID") or ctx.get("device_id", "")),
            "timestamp":   str(raw_payload.get("event_time") or raw_payload.get("eventTime") or raw_payload.get("timestamp") or ""),
            "event":       event,
            "source":      "nfc",
            "protocol":    "acs_push",
        }

    @classmethod
    def detect(cls, raw_payload: dict) -> bool:
        return ("card_holder_id" in raw_payload or "cardholderID" in raw_payload) or \
               ("reader_id" in raw_payload and "event_time" in raw_payload)


class HIDAdapter(BaseReaderAdapter):
    """HID Global / OSDP payload."""
    reader_type = "hid"

    def normalize(self, raw_payload: dict, context: dict | None = None) -> dict:
        ctx = context or {}
        raw_type = str(raw_payload.get("readerType") or raw_payload.get("reader_type") or "entry").lower()
        event = "check_in" if raw_type in {"entry", "in", "check_in", "in_reader"} else "check_out"
        return {
            "employee_id": str(raw_payload.get("credentialHolderID") or raw_payload.get("cardholder_id") or raw_payload.get("cardholderID") or ""),
            "device_id":   str(raw_payload.get("deviceOID") or raw_payload.get("device_id") or ctx.get("device_id", "")),
            "timestamp":   str(raw_payload.get("dateTime") or raw_payload.get("date_time") or raw_payload.get("timestamp") or ""),
            "event":       event,
            "source":      "nfc",
            "protocol":    "hid_push",
        }

    @classmethod
    def detect(cls, raw_payload: dict) -> bool:
        return "credentialHolderID" in raw_payload or "deviceOID" in raw_payload


# Ordered list – more specific adapters first, generic last
READER_ADAPTERS: list[BaseReaderAdapter] = [ZKTecoAdapter(), ACSAdapter(), HIDAdapter(), BaseReaderAdapter()]


def auto_detect_reader_adapter(raw_payload: dict) -> BaseReaderAdapter:
    """Return the first adapter that claims to recognise the payload."""
    for adapter in READER_ADAPTERS[:-1]:          # skip generic fallback in auto-detect
        if adapter.detect(raw_payload):
            return adapter
    return READER_ADAPTERS[-1]                    # generic fallback


# ─────────────────────────────────────────────────────────────────────────────


def normalize_scan_source(value):
    normalized = str(value or "").strip().lower()
    if normalized in {"nfc", "qr", "wallet", "rfid"}:
        return normalized
    if normalized == "android":
        return "nfc"
    if normalized == "iphone":
        return "wallet"
    return "nfc"


def _identity_token_secret():
    return (
        (os.getenv("BAUPASS_IDENTITY_TOKEN_SECRET") or "").strip()
        or (os.getenv("BAUPASS_RECOVERY_SECRET") or "").strip()
        or "baupass-dev-identity-secret-change-me"
    )


def _hash_identity_token(raw_token):
    payload = f"{_identity_token_secret()}::{str(raw_token or '').strip()}"
    return hashlib.sha256(payload.encode("utf-8")).hexdigest()


def _new_worker_identity_token_value(worker_id, company_id):
    now_bucket = str(int(time.time()))
    nonce = secrets.token_urlsafe(24)
    digest = hashlib.sha256(f"{worker_id}:{company_id}:{now_bucket}:{nonce}".encode("utf-8")).hexdigest()[:32]
    return f"wid_{digest}"


def _get_worker_identity_token(db, worker_id):
    return db.execute(
        """
        SELECT *
        FROM worker_identity_tokens
        WHERE worker_id = ?
        LIMIT 1
        """,
        (worker_id,),
    ).fetchone()


def issue_worker_identity_token(db, worker, rotate=False):
    existing = _get_worker_identity_token(db, worker["id"])
    now_value = now_iso()
    expires_at = (datetime.now(timezone.utc) + timedelta(days=IDENTITY_TOKEN_TTL_DAYS)).replace(tzinfo=None).isoformat() + "Z"
    raw_token = _new_worker_identity_token_value(worker["id"], worker["company_id"])
    token_hash = _hash_identity_token(raw_token)
    token_hint = raw_token[-6:]

    if existing:
        if not rotate and str(existing["status"] or "") == "active" and str(existing["expires_at"] or "") > now_value:
            return {
                "created": False,
                "rotated": False,
                "token": None,
                "status": str(existing["status"] or ""),
                "tokenHint": str(existing["token_hint"] or ""),
                "issuedAt": str(existing["issued_at"] or ""),
                "expiresAt": str(existing["expires_at"] or ""),
                "lastUsedAt": str(existing["last_used_at"] or ""),
            }
        db.execute(
            """
            UPDATE worker_identity_tokens
            SET token_hash = ?,
                token_hint = ?,
                status = 'active',
                issued_at = ?,
                expires_at = ?,
                last_used_at = NULL,
                last_device_id = '',
                last_source = ''
            WHERE id = ?
            """,
            (token_hash, token_hint, now_value, expires_at, existing["id"]),
        )
        return {
            "created": False,
            "rotated": True,
            "token": raw_token,
            "status": "active",
            "tokenHint": token_hint,
            "issuedAt": now_value,
            "expiresAt": expires_at,
            "lastUsedAt": "",
        }

    token_row_id = f"wit-{secrets.token_hex(8)}"
    db.execute(
        """
        INSERT INTO worker_identity_tokens (
            id, worker_id, company_id, token_hash, token_hint, status, issued_at, expires_at
        ) VALUES (?, ?, ?, ?, ?, 'active', ?, ?)
        """,
        (token_row_id, worker["id"], worker["company_id"], token_hash, token_hint, now_value, expires_at),
    )
    return {
        "created": True,
        "rotated": False,
        "token": raw_token,
        "status": "active",
        "tokenHint": token_hint,
        "issuedAt": now_value,
        "expiresAt": expires_at,
        "lastUsedAt": "",
    }


def _resolve_worker_by_identity_token(db, raw_token):
    token_value = str(raw_token or "").strip()
    if not token_value:
        return None, "missing_token"
    if len(token_value) > 256:
        return None, "invalid_token"
    # Dynamic QR token (DQR:badgeId:window:sig) — validate and resolve by badge
    if token_value.startswith("DQR:"):
        dqr_badge_id, dqr_err = _dqr_validate(token_value)
        if dqr_err:
            return None, dqr_err
        badge_lookup = normalize_badge_id(dqr_badge_id)
        row = db.execute(
            "SELECT * FROM workers WHERE badge_id_lookup = ? AND deleted_at IS NULL LIMIT 1",
            (badge_lookup,),
        ).fetchone()
        if not row:
            return None, "invalid_token"
        if row["deleted_at"]:
            return None, "worker_not_available"
        return row, ""

    token_hash = _hash_identity_token(token_value)
    row = db.execute(
        """
        SELECT
            w.*, 
            t.id AS identity_token_id,
            t.status AS identity_token_status,
            t.expires_at AS identity_token_expires_at
        FROM worker_identity_tokens t
        JOIN workers w ON w.id = t.worker_id
        WHERE t.token_hash = ?
        LIMIT 1
        """,
        (token_hash,),
    ).fetchone()
    if not row:
        return None, "invalid_token"
    if str(row["identity_token_status"] or "") != "active":
        return None, "token_revoked"
    expires_at = str(row["identity_token_expires_at"] or "")
    if expires_at and expires_at < now_iso():
        return None, "token_expired"
    if row["deleted_at"]:
        return None, "worker_not_available"
    return row, ""


def build_normalized_device_event(payload, turnstile_user, worker, direction, scan_mode, received_at_iso):
    # Device abstraction: every connector writes the same event shape.
    turnstile_id = ""
    if isinstance(turnstile_user, sqlite3.Row):
        turnstile_id = str(turnstile_user["id"] or "")
    elif isinstance(turnstile_user, dict):
        turnstile_id = str(turnstile_user.get("id") or "")

    raw_device_id = str(payload.get("deviceId") or payload.get("readerId") or turnstile_id).strip()
    device_id = clean_id_input(raw_device_id, max_len=64) or (turnstile_id or "gate-unknown")
    protocol = normalize_device_protocol(payload.get("protocol") or "http")
    source = scan_mode if scan_mode in {"rfid", "nfc", "wallet", "qr"} else "rfid"
    event_name = "check_in" if direction == "check-in" else "check_out"
    return {
        "employee_id": str(worker["id"]),
        "company_id": str(worker["company_id"]),
        "device_id": device_id,
        "event": event_name,
        "timestamp": received_at_iso,
        "source": source,
        "protocol": protocol,
    }


def should_drop_duplicate_device_event(normalized_event):
    now_ts = time.time()
    dedup_bucket = int(now_ts // DEVICE_EVENT_DEDUP_SECONDS)
    dedup_key = "|".join(
        [
            str(normalized_event.get("employee_id") or ""),
            str(normalized_event.get("device_id") or ""),
            str(normalized_event.get("event") or ""),
            str(dedup_bucket),
        ]
    )
    with _device_event_dedup_lock:
        is_duplicate = dedup_key in _device_event_dedup_state
        if not is_duplicate:
            _device_event_dedup_state[dedup_key] = now_ts
        cutoff_ts = now_ts - max(DEVICE_EVENT_DEDUP_SECONDS * 4, 20)
        stale_keys = [key for key, ts in _device_event_dedup_state.items() if not isinstance(ts, (int, float)) or ts < cutoff_ts]
        for stale_key in stale_keys:
            _device_event_dedup_state.pop(stale_key, None)
    return is_duplicate


def build_device_event_uid(payload, normalized_event):
    client_event_id = clean_id_input(payload.get("eventId") or payload.get("clientEventId"), max_len=80)
    if client_event_id:
        return f"client:{client_event_id}"
    fingerprint_input = "|".join(
        [
            str(normalized_event.get("employee_id") or ""),
            str(normalized_event.get("device_id") or ""),
            str(normalized_event.get("event") or ""),
            str(normalized_event.get("timestamp") or ""),
            str(normalized_event.get("source") or ""),
        ]
    )
    digest = hashlib.sha256(fingerprint_input.encode("utf-8")).hexdigest()
    return f"fp:{digest}"


def insert_device_ingest_event(db, event_uid, normalized_event, raw_payload, received_at_iso):
    event_id = f"ing-{secrets.token_hex(10)}"
    try:
        db.execute(
            """
            INSERT INTO device_ingest_events (
                id, event_uid, device_id, company_id, employee_id, source, protocol,
                event_name, event_timestamp, received_at, outcome,
                raw_payload_json, normalized_payload_json
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'received', ?, ?)
            """,
            (
                event_id,
                event_uid,
                str(normalized_event.get("device_id") or ""),
                str(normalized_event.get("company_id") or ""),
                str(normalized_event.get("employee_id") or ""),
                str(normalized_event.get("source") or ""),
                str(normalized_event.get("protocol") or "http"),
                str(normalized_event.get("event") or ""),
                str(normalized_event.get("timestamp") or received_at_iso),
                received_at_iso,
                json.dumps(raw_payload or {}, ensure_ascii=False),
                json.dumps(normalized_event or {}, ensure_ascii=False),
            ),
        )
        return True
    except sqlite3.IntegrityError:
        return False


