def upsert_device_event_dead_letter(db, event_uid, normalized_event, raw_payload, reason, last_error=""):
    existing = db.execute(
        "SELECT id FROM device_event_dead_letters WHERE event_uid = ? LIMIT 1",
        (str(event_uid or ""),),
    ).fetchone()
    if existing:
        db.execute(
            """
            UPDATE device_event_dead_letters
            SET reason = ?,
                last_error = ?,
                raw_payload_json = ?,
                normalized_payload_json = ?,
                failed_at = ?,
                resolved_at = NULL
            WHERE event_uid = ?
            """,
            (
                str(reason or "processing_failed"),
                str(last_error or ""),
                json.dumps(raw_payload or {}, ensure_ascii=False),
                json.dumps(normalized_event or {}, ensure_ascii=False),
                now_iso(),
                str(event_uid or ""),
            ),
        )
        return

    db.execute(
        """
        INSERT INTO device_event_dead_letters (
            id, event_uid, company_id, device_id, employee_id, reason, last_error,
            raw_payload_json, normalized_payload_json, failed_at
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            f"ddl-{secrets.token_hex(8)}",
            str(event_uid or ""),
            str(normalized_event.get("company_id") or ""),
            str(normalized_event.get("device_id") or ""),
            str(normalized_event.get("employee_id") or ""),
            str(reason or "processing_failed"),
            str(last_error or ""),
            json.dumps(raw_payload or {}, ensure_ascii=False),
            json.dumps(normalized_event or {}, ensure_ascii=False),
            now_iso(),
        ),
    )


def normalize_work_time_value(value):
    normalized = str(value or "").strip()
    if not normalized:
        return ""
    # Browsers often send HH:MM:SS from <input type="time">; store HH:MM only.
    if len(normalized) >= 8 and normalized[2] == ":" and normalized[5] == ":":
        normalized = normalized[:5]
    elif len(normalized) > 5:
        normalized = normalized[:5]
    if not re.fullmatch(r"(?:[01]\d|2[0-3]):[0-5]\d", normalized):
        raise ValueError("invalid_work_time")
    return normalized


def get_effective_work_start_time(db, worker_id):
    row = db.execute(
        """
        SELECT c.work_start_time AS company_work_start_time, s.work_start_time AS global_work_start_time
        FROM workers w
        LEFT JOIN companies c ON c.id = w.company_id
        LEFT JOIN settings s ON s.id = 1
        WHERE w.id = ?
        LIMIT 1
        """,
        (worker_id,),
    ).fetchone()
    if not row:
        return ""
    return str(row["company_work_start_time"] or row["global_work_start_time"] or "").strip()


def ensure_unique_physical_card_id_or_raise(db, physical_card_id, worker_id_to_exclude=None):
    if not physical_card_id:
        return
    if worker_id_to_exclude:
        duplicate = db.execute(
            """
            SELECT id
            FROM workers
            WHERE physical_card_id = ? AND id != ? AND deleted_at IS NULL
            LIMIT 1
            """,
            (physical_card_id, worker_id_to_exclude),
        ).fetchone()
    else:
        duplicate = db.execute(
            """
            SELECT id
            FROM workers
            WHERE physical_card_id = ? AND deleted_at IS NULL
            LIMIT 1
            """,
            (physical_card_id,),
        ).fetchone()
    if duplicate:
        raise ValueError("duplicate_physical_card_id")


def create_access_log_entry(db, worker_id, direction, gate, note, timestamp_value=None, worker_type="worker"):
    log_id = f"log-{secrets.token_hex(6)}"
    late = 0
    if direction == "check-in" and worker_type != "visitor":
        try:
            work_start = get_effective_work_start_time(db, worker_id)
            if work_start and ":" in work_start:
                from datetime import datetime as _dt
                now_local = _dt.now()
                sh, sm = int(work_start.split(":")[0]), int(work_start.split(":")[1])
                if (now_local.hour, now_local.minute) > (sh, sm):
                    late = 1
        except Exception:
            pass
    db.execute(
        "INSERT INTO access_logs (id, worker_id, direction, gate, note, timestamp, checked_in_late) VALUES (?, ?, ?, ?, ?, ?, ?)",
        (
            log_id,
            worker_id,
            direction,
            gate,
            note,
            timestamp_value or now_iso(),
            late,
        ),
    )
    return log_id


def create_worker_app_session(db, worker, device_payload=None):
    session_token = secrets.token_urlsafe(28)
    expires_at = resolve_worker_session_expiry_iso(worker)
    site_coordinates = ensure_worker_site_coordinates(db, worker)
    db.execute(
        "INSERT INTO worker_app_sessions (token, worker_id, expires_at, bound_device_id) VALUES (?, ?, ?, ?)",
        (session_token, worker["id"], expires_at, ""),
    )
    db.commit()
    worker_payload = dict(worker)
    if site_coordinates:
        worker_payload["site_latitude"] = float(site_coordinates[0])
        worker_payload["site_longitude"] = float(site_coordinates[1])
    session_data = {
        "token": session_token,
        "worker": serialize_worker_for_app(worker_payload, db=db, company_id=worker["company_id"]),
        "sessionExpiresAt": expires_at,
        "cardType": normalize_worker_type(worker["worker_type"]),
    }
    session_data.update(enrich_worker_mobile_session(db, worker, session_token, expires_at, device_payload))
    return session_data


def enrich_worker_mobile_session(db, worker, session_token, expires_at, device_payload=None):
    from backend.app.platform.security.worker_devices import (
        bind_worker_device,
        issue_worker_access_jwt,
        worker_device_binding_enabled,
        worker_jwt_enabled,
    )

    extras = {"deviceBindingRequired": worker_device_binding_enabled()}
    if device_payload:
        bind_result = bind_worker_device(db, worker, device_payload, session_token)
        extras.update(bind_result)
    if worker_jwt_enabled():
        extras["jwt"] = issue_worker_access_jwt(
            worker_id=worker["id"],
            device_id=str(extras.get("deviceId") or ""),
            session_token=session_token,
            expires_at_iso=expires_at,
        )
    return extras


def resolve_worker_session_token_from_bearer(raw_token):
    from backend.app.platform.security.worker_devices import looks_like_jwt, verify_worker_access_jwt

    token = str(raw_token or "").strip()
    if not token:
        return None, None
    if looks_like_jwt(token):
        claims = verify_worker_access_jwt(token)
        if not claims:
            return None, None
        return claims["session_token"], claims
    return token, None


def validate_worker_bound_device_or_raise(db, worker_id, session_token):
    from backend.app.platform.security.worker_devices import validate_bound_device_for_request

    device_header = str(
        request.headers.get("X-Device-Id") or request.headers.get("X-Worker-Device-Id") or ""
    ).strip()
    ok, error_code = validate_bound_device_for_request(db, worker_id, session_token, device_header)
    if ok:
        return None
    messages = {
        "missing_device_id": "Registriertes Geraet erforderlich (X-Device-Id Header fehlt).",
        "device_not_bound": "Dieses Geraet ist nicht fuer die aktive Sitzung freigegeben.",
        "device_not_active": "Geraetebindung ist deaktiviert. Bitte erneut anmelden.",
    }
    return jsonify({"error": error_code, "message": messages.get(error_code, error_code)}), 403


