@app.get("/api/analytics/worker-trends")
@require_admin_session
def analytics_worker_trends():
    """Arbeitszeit-Trends: Durchschnittliche Schichtten pro Woche."""
    from backend.app.db.connection import get_read_connection

    user = g.admin_user
    company_id = user["company_id"]
    
    now = datetime.now()
    week_ago = now - timedelta(days=7)
    week_ago_str = week_ago.strftime("%Y-%m-%d")

    with get_read_connection() as db:
        trends = db.execute(
        """
        SELECT
            DATE(al.timestamp) as work_date,
            COUNT(DISTINCT al.worker_id) as active_workers,
            AVG(
                CASE
                    WHEN al.direction = 'check-in' THEN 1
                    ELSE 0
                END
            ) * 100 AS checkin_rate
        FROM access_logs al
        WHERE al.timestamp > ?
          AND al.worker_id IN (SELECT id FROM workers WHERE company_id = ? AND deleted_at IS NULL)
        GROUP BY DATE(al.timestamp)
        ORDER BY work_date DESC
        LIMIT 7
        """,
            (week_ago_str, company_id),
        ).fetchall()

        result = []
        for row in trends:
            result.append({
                "date": row["work_date"],
                "activeWorkers": row["active_workers"],
                "checkins": row["active_workers"],
                "count": row["active_workers"],
                "checkinRate": round(row["checkin_rate"], 1) if row["checkin_rate"] else 0,
            })

    daily = list(reversed(result))
    return jsonify({"trends": result, "daily": daily, "days": daily})


@app.get("/api/analytics/document-health")
@require_admin_session
def analytics_document_health():
    """Doku-Health: Score pro Dokumenttyp."""
    from backend.app.db.connection import get_read_connection

    user = g.admin_user
    company_id = user["company_id"]

    with get_read_connection() as db:
        total_workers = db.execute(
            "SELECT COUNT(*) as cnt FROM workers WHERE company_id = ? AND deleted_at IS NULL",
            (company_id,),
        ).fetchone()["cnt"]

        doc_types = db.execute(
        """
        SELECT
            doc_type,
            COUNT(DISTINCT worker_id) as workers_with_doc,
            COUNT(*) as total_docs
        FROM worker_documents
        WHERE company_id = ?
        GROUP BY doc_type
        ORDER BY doc_type
        """,
            (company_id,),
        ).fetchall()

        health_data = []
        for row in doc_types:
            coverage = round((row["workers_with_doc"] / max(1, total_workers)) * 100, 0)
            health_data.append({
                "docType": row["doc_type"],
                "coverage": int(coverage),
                "workersWithDoc": row["workers_with_doc"],
                "totalDocs": row["total_docs"],
            })

        today = datetime.now().strftime("%Y-%m-%d")
        in_30 = (datetime.now() + timedelta(days=30)).strftime("%Y-%m-%d")
        valid = db.execute(
            """
            SELECT COUNT(*) AS cnt FROM worker_documents
            WHERE company_id = ? AND (expiry_date IS NULL OR expiry_date = '' OR expiry_date > ?)
            """,
            (company_id, in_30),
        ).fetchone()["cnt"]
        expiring = db.execute(
            """
            SELECT COUNT(*) AS cnt FROM worker_documents
            WHERE company_id = ? AND expiry_date IS NOT NULL AND expiry_date != ''
              AND expiry_date > ? AND expiry_date <= ?
            """,
            (company_id, today, in_30),
        ).fetchone()["cnt"]
        expired = db.execute(
            """
            SELECT COUNT(*) AS cnt FROM worker_documents
            WHERE company_id = ? AND expiry_date IS NOT NULL AND expiry_date != ''
              AND expiry_date < ?
            """,
            (company_id, today),
        ).fetchone()["cnt"]
        with_doc = db.execute(
            "SELECT COUNT(DISTINCT worker_id) AS cnt FROM worker_documents WHERE company_id = ?",
            (company_id,),
        ).fetchone()["cnt"]
        missing = max(0, int(total_workers) - int(with_doc))

    return jsonify({
        "docHealth": health_data,
        "totalWorkers": total_workers,
        "valid": int(valid),
        "expiring": int(expiring),
        "expired": int(expired),
        "missing": int(missing),
    })


def _company_work_start_hm(db, company_id: str) -> tuple[int, int, str]:
    """Return (hour, minute, HH:MM:SS) from company work_start_time or 08:00."""
    row = db.execute(
        "SELECT work_start_time FROM companies WHERE id = ?",
        (company_id,),
    ).fetchone()
    raw = str(row["work_start_time"] if row else "").strip()
    try:
        normalized = normalize_work_time_value(raw) if raw else "08:00"
    except ValueError:
        normalized = "08:00"
    parts = normalized.split(":")
    hour = int(parts[0]) if parts else 8
    minute = int(parts[1]) if len(parts) > 1 else 0
    return hour, minute, f"{hour:02d}:{minute:02d}:00"


@app.get("/api/analytics/punctuality-report")
@require_admin_session
def analytics_punctuality_report():
    """Pünktlichkeits-Report: Verspätungen vs. firmen-Arbeitsbeginn."""
    from backend.app.db.connection import get_read_connection

    user = g.admin_user
    company_id = user["company_id"]
    today_prefix = datetime.now().strftime("%Y-%m-%d")

    with get_read_connection() as db:
        start_h, start_m, start_label = _company_work_start_hm(db, company_id)
        rows = db.execute(
            """
            SELECT
                w.id,
                w.first_name,
                w.last_name,
                TIME(al.timestamp) AS checkin_time,
                al.timestamp AS checkin_at
            FROM workers w
            JOIN access_logs al ON w.id = al.worker_id
            WHERE w.company_id = ?
              AND al.timestamp LIKE ?
              AND al.direction = 'check-in'
              AND al.timestamp = (
                  SELECT MAX(al2.timestamp)
                  FROM access_logs al2
                  WHERE al2.worker_id = w.id AND al2.timestamp LIKE ?
              )
            ORDER BY al.timestamp DESC
            LIMIT 80
            """,
            (company_id, f"{today_prefix}%", f"{today_prefix}%"),
        ).fetchall()

        late_workers = []
        for w in rows:
            try:
                ts = str(w["checkin_at"] or "")
                if "T" in ts:
                    time_part = ts.split("T", 1)[1][:8]
                else:
                    time_part = str(w["checkin_time"] or "00:00:00")
                parts = time_part.split(":")
                ch = int(parts[0]) if parts else 0
                cm = int(parts[1]) if len(parts) > 1 else 0
                check_min = ch * 60 + cm
                start_min = start_h * 60 + start_m
                if check_min <= start_min:
                    continue
                late_workers.append(
                    {
                        "name": f"{w['first_name']} {w['last_name']}".strip(),
                        "checkinTime": w["checkin_time"],
                        "minutesLate": check_min - start_min,
                    }
                )
            except (TypeError, ValueError):
                continue
        late_workers.sort(key=lambda x: x["minutesLate"], reverse=True)
        late_workers = late_workers[:25]

        late_count = len(late_workers)
        total_count = db.execute(
            "SELECT COUNT(*) as cnt FROM workers WHERE company_id = ? AND deleted_at IS NULL",
            (company_id,),
        ).fetchone()["cnt"]

        punctuality_rate = round(((total_count - late_count) / max(1, total_count)) * 100, 1)

    return jsonify({
        "punctualityRate": punctuality_rate,
        "workStartTime": start_label[:5],
        "lateWorkers": late_workers,
        "totalWorkers": total_count,
    })


