@app.get("/api/shift/assignments")
@require_worker_session
def shift_get_assignments():
    """Mitarbeiter: Seine Schicht-Zuweisungen auflisten."""
    db = get_db()
    worker = g.worker

    assignments = db.execute(
        """
        SELECT
            id, start_time, end_time, site, status, notes
        FROM shift_assignments
        WHERE worker_id = ? AND status != 'cancelled'
          AND end_time >= datetime('now', '-1 day')
        ORDER BY start_time ASC
        LIMIT 30
        """,
        (worker["id"],)
    ).fetchall()

    result = []
    for a in assignments:
        result.append({
            "id": a["id"],
            "startTime": a["start_time"],
            "endTime": a["end_time"],
            "site": a["site"],
            "status": a["status"],
            "notes": a["notes"],
        })

    return jsonify({"assignments": result})


@app.post("/api/shift/assignments")
@require_admin_session
def shift_create_assignment():
    """Admin: Neue Schicht-Zuweisung erstellen."""
    db = get_db()
    user = g.admin_user
    payload = request.get_json(silent=True) or {}

    worker_id = str(payload.get("workerId") or "").strip()
    start_time = str(payload.get("startTime") or "").strip()
    end_time = str(payload.get("endTime") or "").strip()
    site = str(payload.get("site") or "").strip()
    notes = str(payload.get("notes") or "").strip()

    if not worker_id or not start_time or not end_time:
        return jsonify({"error": "missing_fields"}), 400

    worker = db.execute("SELECT * FROM workers WHERE id = ?", (worker_id,)).fetchone()
    if not worker or worker["company_id"] != user["company_id"]:
        return jsonify({"error": "not_found"}), 404

    assign_id = f"shift-{secrets.token_hex(8)}"
    db.execute(
        """
        INSERT INTO shift_assignments (id, company_id, site, worker_id, assigned_at, start_time, end_time, status, notes, created_by_user_id)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (assign_id, user["company_id"], site or worker["site"], worker_id, now_iso(), start_time, end_time, "scheduled", notes, user["id"])
    )
    db.commit()

    push_delivery = {"pushSent": 0}
    try:
        from backend.app.platform.push.automation import push_to_worker

        push_delivery = push_to_worker(
            db,
            worker_id,
            "Neue Schicht",
            f"{start_time[:16]} – {end_time[:16]}{(' · ' + site) if site else ''}",
            tag="attendance-reminder",
            company_id=user["company_id"],
        )
    except Exception:
        pass

    return jsonify({"ok": True, "assignmentId": assign_id, "pushDelivery": push_delivery})


@app.get("/api/foreman/shift-assignments")
@require_admin_session
def foreman_shift_assignments():
    """Foreman: anstehende Schichten der Firma."""
    db = get_db()
    user = g.admin_user
    company_id = user["company_id"]
    rows = db.execute(
        """
        SELECT sa.id, sa.worker_id, sa.site, sa.start_time, sa.end_time, sa.status, sa.notes,
               w.first_name, w.last_name, w.badge_id
        FROM shift_assignments sa
        JOIN workers w ON w.id = sa.worker_id
        WHERE sa.company_id = ? AND sa.status != 'cancelled'
          AND sa.end_time >= datetime('now', '-1 day')
        ORDER BY sa.start_time ASC
        LIMIT 80
        """,
        (company_id,),
    ).fetchall()
    assignments = []
    for r in rows:
        assignments.append(
            {
                "id": r["id"],
                "workerId": r["worker_id"],
                "workerName": f"{r['first_name']} {r['last_name']}".strip(),
                "badgeId": r["badge_id"],
                "site": r["site"],
                "startTime": r["start_time"],
                "endTime": r["end_time"],
                "status": r["status"],
                "notes": r["notes"],
            }
        )
    return jsonify({"assignments": assignments, "total": len(assignments)})


