# ── Dynamic QR helpers ────────────────────────────────────────────────────────
_DQR_WINDOW_SECONDS = 60  # how long each QR token is valid
_DQR_GRACE_WINDOWS = 1  # accept N extra previous windows (clock skew tolerance)


def _dqr_secret():
    """Per-installation secret used to sign dynamic QR tokens."""
    return (
        (os.getenv("BAUPASS_DQR_SECRET") or "").strip()
        or _identity_token_secret()
    )


def _dqr_window(ts: float | None = None) -> int:
    return int((ts or time.time()) // _DQR_WINDOW_SECONDS)


def _dqr_sign(badge_id: str, window: int) -> str:
    msg = f"{badge_id}:{window}".encode()
    return hmac_mod.new(_dqr_secret().encode(), msg, "sha256").hexdigest()[:16]


def _dqr_build(badge_id: str, window: int | None = None) -> str:
    w = window if window is not None else _dqr_window()
    sig = _dqr_sign(badge_id, w)
    return f"DQR:{badge_id}:{w}:{sig}"


def _dqr_validate(token: str) -> tuple[str | None, str]:
    """Returns (badge_id, error). error is '' on success."""
    if not token.startswith("DQR:"):
        return None, "not_dynamic_qr"
    parts = token.split(":", 3)
    if len(parts) != 4:
        return None, "malformed_dqr"
    _, badge_id, window_str, sig = parts
    try:
        window = int(window_str)
    except ValueError:
        return None, "malformed_dqr"
    current = _dqr_window()
    # Accept current + previous N windows (grace period for scanning delay)
    if not (current - _DQR_GRACE_WINDOWS <= window <= current):
        return None, "dqr_expired"
    expected = _dqr_sign(badge_id, window)
    if not hmac_mod.compare_digest(sig, expected):
        return None, "dqr_invalid_signature"
    return badge_id, ""


def _hce_handshake_secret():
    return (
        (os.getenv("BAUPASS_HCE_SECRET") or "").strip()
        or _identity_token_secret()
    )


def _hce_sign_handshake(worker_id: str, badge_id: str, device_id: str, nonce: str, issued_at: str, expires_at: str) -> str:
    msg = f"{worker_id}|{badge_id}|{device_id}|{nonce}|{issued_at}|{expires_at}".encode("utf-8")
    return hmac_mod.new(_hce_handshake_secret().encode("utf-8"), msg, "sha256").hexdigest()


def _hce_device_payload_to_sign(device_id: str, nonce: str, client_ts: str) -> str:
    return f"{device_id}|{nonce}|{client_ts}"


def _hce_sign_device_payload(device_secret: str, device_id: str, nonce: str, client_ts: str) -> str:
    payload = _hce_device_payload_to_sign(device_id, nonce, client_ts).encode("utf-8")
    return hmac_mod.new(device_secret.encode("utf-8"), payload, "sha256").hexdigest()


def _hce_verify_device_signature_v2(public_key_b64: str, device_id: str, nonce: str, client_ts: str, signature_b64: str) -> bool:
    try:
        key_bytes = base64.b64decode(str(public_key_b64 or ""))
        signature = base64.b64decode(str(signature_b64 or ""))
        payload = _hce_device_payload_to_sign(device_id, nonce, client_ts).encode("utf-8")
        public_key = serialization.load_der_public_key(key_bytes)
        if isinstance(public_key, ec.EllipticCurvePublicKey):
            public_key.verify(signature, payload, ec.ECDSA(hashes.SHA256()))
            return True
        return False
    except Exception:
        return False


def _load_public_key_from_string(public_key_str: str):
    raw = str(public_key_str or "").strip()
    if not raw:
        return None
    try:
        if "-----BEGIN" in raw:
            return serialization.load_pem_public_key(raw.encode("utf-8"))
    except Exception:
        pass
    try:
        der_bytes = base64.b64decode(raw)
        return serialization.load_der_public_key(der_bytes)
    except Exception:
        return None


def _verify_device_biometric_signature(public_key_str: str, device_id: str, timestamp: str, signature_str: str) -> bool:
    public_key = _load_public_key_from_string(public_key_str)
    if public_key is None:
        return False

    try:
        signature = base64.b64decode(signature_str)
    except Exception:
        try:
            signature = bytes.fromhex(signature_str)
        except Exception:
            return False

    message = f"{device_id}|{timestamp}".encode("utf-8")
    try:
        if isinstance(public_key, ec.EllipticCurvePublicKey):
            public_key.verify(signature, message, ec.ECDSA(hashes.SHA256()))
        elif isinstance(public_key, rsa.RSAPublicKey):
            public_key.verify(signature, message, padding.PKCS1v15(), hashes.SHA256())
        else:
            public_key.verify(signature, message)
        return True
    except Exception:
        return False


def _validate_biometric_auth_timestamp(timestamp: str, max_skew_seconds: int = 120) -> bool:
    try:
        ts_int = int(str(timestamp or "").strip())
    except (TypeError, ValueError):
        return False

    now_ms = int(time.time() * 1000)
    if ts_int > 10**11:
        return abs(now_ms - ts_int) <= max_skew_seconds * 1000
    return abs(now_ms - ts_int * 1000) <= max_skew_seconds * 1000


def _hce_validate_client_timestamp(client_ts: str, max_skew_ms: int = 120000) -> bool:
    try:
        ts_int = int(str(client_ts or "").strip())
    except (TypeError, ValueError):
        return False
    now_ms = int(time.time() * 1000)
    return abs(now_ms - ts_int) <= max_skew_ms


@require_worker_session
def worker_app_hce_device_register():
    worker = g.worker
    payload = request.get_json(silent=True) or {}
    device_id = clean_id_input(payload.get("deviceId") or payload.get("device_id"), max_len=80)
    platform = clean_text_input(payload.get("platform") or "android", max_len=24) or "android"
    app_version = clean_text_input(payload.get("appVersion") or "", max_len=40)
    device_public_key = str(payload.get("devicePublicKey") or "").strip()
    signature_algo = clean_text_input(payload.get("signatureAlgo") or "", max_len=32)
    try:
        requested_trust_version = int(payload.get("trustVersion") or 1)
    except (TypeError, ValueError):
        requested_trust_version = 1
    trust_version = 2 if requested_trust_version >= 2 and device_public_key else 1
    if not device_id:
        return jsonify({"error": "missing_device_id"}), 400

    db = get_db()
    now_value = now_iso()
    device_secret = secrets.token_hex(24)
    existing = db.execute(
        """
        SELECT id
        FROM hce_device_trust
        WHERE worker_id = ? AND device_id = ?
        LIMIT 1
        """,
        (worker["id"], device_id),
    ).fetchone()

    if existing:
        existing_row = db.execute(
            "SELECT status FROM hce_device_trust WHERE id = ? LIMIT 1",
            (existing["id"],),
        ).fetchone()
        if existing_row and str(existing_row["status"] or "") == "revoked":
            return jsonify({"error": "device_revoked_contact_admin"}), 403
        db.execute(
            """
            UPDATE hce_device_trust
            SET company_id = ?,
                platform = ?,
                app_version = ?,
                device_secret = ?,
                device_public_key = ?,
                signature_algo = ?,
                trust_version = ?,
                status = 'active',
                last_seen_at = ?
            WHERE id = ?
            """,
            (worker["company_id"], platform, app_version, device_secret, device_public_key, signature_algo, trust_version, now_value, existing["id"]),
        )
        record_id = existing["id"]
    else:
        record_id = f"hce-dev-{secrets.token_hex(6)}"
        db.execute(
            """
            INSERT INTO hce_device_trust (
                id, worker_id, company_id, device_id, platform, app_version, device_secret, device_public_key, signature_algo, trust_version, status, created_at, last_seen_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'active', ?, ?)
            """,
            (record_id, worker["id"], worker["company_id"], device_id, platform, app_version, device_secret, device_public_key, signature_algo, trust_version, now_value, now_value),
        )
    db.commit()
    return jsonify(
        {
            "ok": True,
            "deviceTrustId": record_id,
            "deviceId": device_id,
            "deviceSecret": device_secret,
            "trustVersion": trust_version,
            "signatureAlgo": signature_algo,
            "registeredAt": now_value,
            "status": "active",
        }
    )


@require_worker_session
def worker_app_dynamic_qr():
    """Return a fresh short-lived signed QR token for the worker's badge."""
    worker = g.worker
    badge_id = str(worker["badge_id"] or "").strip()
    if not badge_id:
        return jsonify({"error": "badge_id_missing"}), 422
    now_ts = time.time()
    window = _dqr_window(now_ts)
    token = _dqr_build(badge_id, window)
    elapsed_in_window = int(now_ts % _DQR_WINDOW_SECONDS)
    remaining_sec = _DQR_WINDOW_SECONDS - elapsed_in_window
    return jsonify(
        {
            "qrToken": token,
            "windowSec": _DQR_WINDOW_SECONDS,
            "remainingSec": remaining_sec,
            "badgeId": badge_id,
        }
    )


@require_worker_session
def worker_app_hce_bootstrap():
    """Bootstrap endpoint for Android HCE companion app.

    Returns a short-lived payload token plus a signed handshake envelope
    bound to worker + device_id so native clients can provision HCE state.
    """
    worker = g.worker
    payload = request.get_json(silent=True) or {}
    badge_id = str(worker["badge_id"] or "").strip()
    if not badge_id:
        return jsonify({"error": "badge_id_missing"}), 422

    device_id = clean_id_input(payload.get("deviceId") or payload.get("device_id"), max_len=80)
    if not device_id:
        return jsonify({"error": "missing_device_id"}), 400

    db = get_db()
    trust_row = db.execute(
        """
        SELECT *
        FROM hce_device_trust
        WHERE worker_id = ? AND device_id = ?
        LIMIT 1
        """,
        (worker["id"], device_id),
    ).fetchone()
    if not trust_row:
        return jsonify({"error": "device_not_registered"}), 403
    if str(trust_row["status"] or "") != "active":
        return jsonify({"error": "device_not_active"}), 403

    client_nonce = clean_id_input(payload.get("nonce"), max_len=120)
    client_ts = clean_text_input(payload.get("clientTs"), max_len=40)
    submitted_sig_v1 = str(request.headers.get("X-HCE-Device-Signature") or payload.get("deviceSignature") or "").strip().lower()
    submitted_sig_v2 = str(request.headers.get("X-HCE-Device-Signature-V2") or payload.get("deviceSignatureV2") or "").strip()
    trust_version = int(trust_row["trust_version"] or 1)
    if not client_nonce or not client_ts:
        return jsonify({"error": "missing_device_signature"}), 401
    if not _hce_validate_client_timestamp(client_ts):
        return jsonify({"error": "stale_or_invalid_client_ts"}), 401

    if trust_version >= 2 and str(trust_row["device_public_key"] or ""):
        if not submitted_sig_v2:
            return jsonify({"error": "missing_device_signature_v2"}), 401
        ok_v2 = _hce_verify_device_signature_v2(
            str(trust_row["device_public_key"] or ""),
            device_id,
            client_nonce,
            client_ts,
            submitted_sig_v2,
        )
        if not ok_v2:
            return jsonify({"error": "invalid_device_signature_v2"}), 401
    else:
        if not submitted_sig_v1:
            return jsonify({"error": "missing_device_signature"}), 401
        expected_sig = _hce_sign_device_payload(str(trust_row["device_secret"] or ""), device_id, client_nonce, client_ts)
        if not hmac_mod.compare_digest(submitted_sig_v1, expected_sig):
            return jsonify({"error": "invalid_device_signature"}), 401

    # Replay protection: nonce per device is one-time use within TTL window.
    now_value = now_iso()
    db.execute("DELETE FROM hce_device_nonces WHERE expires_at < ?", (now_value,))
    nonce_row_id = f"hce-nonce-{secrets.token_hex(6)}"
    nonce_expiry = (datetime.now(timezone.utc) + timedelta(minutes=5)).replace(tzinfo=None).isoformat() + "Z"
    try:
        db.execute(
            """
            INSERT INTO hce_device_nonces (id, worker_id, device_id, nonce, created_at, expires_at)
            VALUES (?, ?, ?, ?, ?, ?)
            """,
            (nonce_row_id, worker["id"], device_id, client_nonce, now_value, nonce_expiry),
        )
    except sqlite3.IntegrityError:
        return jsonify({"error": "replayed_nonce"}), 401

    now_ts = time.time()
    now_iso_value = now_value
    window = _dqr_window(now_ts)
    payload_token = _dqr_build(badge_id, window)
    elapsed_in_window = int(now_ts % _DQR_WINDOW_SECONDS)
    remaining_sec = _DQR_WINDOW_SECONDS - elapsed_in_window
    expires_at = (datetime.now(timezone.utc) + timedelta(seconds=max(remaining_sec, 20))).replace(tzinfo=None).isoformat() + "Z"
    nonce = secrets.token_hex(8)
    signature = _hce_sign_handshake(str(worker["id"]), badge_id, device_id, nonce, now_iso_value, expires_at)

    db.execute(
        "UPDATE hce_device_trust SET last_seen_at = ? WHERE id = ?",
        (now_iso_value, trust_row["id"]),
    )
    db.commit()

    return jsonify(
        {
            "protocol": "baupass-hce-v1",
            "aid": "F0010203040506",
            "payloadToken": payload_token,
            "windowSec": _DQR_WINDOW_SECONDS,
            "remainingSec": remaining_sec,
            "workerId": str(worker["id"]),
            "badgeId": badge_id,
            "deviceId": device_id,
            "issuedAt": now_iso_value,
            "expiresAt": expires_at,
            "nonce": nonce,
            "signature": signature,
        }
    )


@require_worker_session
def worker_app_access_last():
    worker = g.worker
    db = get_db()
    feedback = get_latest_worker_gate_feedback(db, worker["id"])
    row = db.execute(
        """
        SELECT id, direction, gate, note, timestamp
        FROM access_logs
        WHERE worker_id = ?
        ORDER BY timestamp DESC, id DESC
        LIMIT 1
        """,
        (worker["id"],),
    ).fetchone()
    if not row:
        return jsonify(
            {
                "hasEvent": False,
                "event": None,
                "hasGateFeedback": bool(feedback),
                "gateFeedback": {
                    "id": str(feedback["id"]),
                    "status": str(feedback["status"] or ""),
                    "direction": str(feedback["direction"] or ""),
                    "gate": str(feedback["gate"] or ""),
                    "message": str(feedback["message"] or ""),
                    "reasonCode": str(feedback["reason_code"] or ""),
                    "source": str(feedback["source"] or ""),
                    "timestamp": str(feedback["created_at"] or ""),
                } if feedback else None,
            }
        )
    return jsonify(
        {
            "hasEvent": True,
            "event": {
                "id": str(row["id"]),
                "direction": str(row["direction"] or ""),
                "gate": str(row["gate"] or ""),
                "note": str(row["note"] or ""),
                "timestamp": str(row["timestamp"] or ""),
            },
            "hasGateFeedback": bool(feedback),
            "gateFeedback": {
                "id": str(feedback["id"]),
                "status": str(feedback["status"] or ""),
                "direction": str(feedback["direction"] or ""),
                "gate": str(feedback["gate"] or ""),
                "message": str(feedback["message"] or ""),
                "reasonCode": str(feedback["reason_code"] or ""),
                "source": str(feedback["source"] or ""),
                "timestamp": str(feedback["created_at"] or ""),
            } if feedback else None,
        }
    )

_pin_fail_counts: dict = {}  # worker_id -> [fail_count, window_start_ts]
_PIN_MAX_ATTEMPTS = 5
_PIN_LOCKOUT_SECONDS = 300  # 5 minutes


def _prune_pin_fail_counts():
    """Remove expired entries to prevent unbounded memory growth."""
    now = time.time()
    expired = [k for k, v in _pin_fail_counts.items() if now - v[1] >= _PIN_LOCKOUT_SECONDS]
    for k in expired:
        _pin_fail_counts.pop(k, None)


@require_worker_session
def worker_app_verify_pin():
    worker = g.worker
    worker_id = worker["id"]
    now = time.time()

    # Periodically prune stale entries (every ~100 calls)
    if len(_pin_fail_counts) > 100:
        _prune_pin_fail_counts()

    # Rate-limit: max 5 failed attempts per worker per 5-minute window
    entry = _pin_fail_counts.get(worker_id)
    if entry:
        fail_count, window_start = entry
        if now - window_start < _PIN_LOCKOUT_SECONDS:
            if fail_count >= _PIN_MAX_ATTEMPTS:
                retry_after = int(_PIN_LOCKOUT_SECONDS - (now - window_start))
                return jsonify({"valid": False, "error": "too_many_attempts", "retryAfter": retry_after}), 429
        else:
            # Window expired — reset
            _pin_fail_counts.pop(worker_id, None)

    payload = request.get_json(silent=True) or {}
    pin_candidate = str(payload.get("pin") or "").strip()
    if not pin_candidate:
        return jsonify({"valid": False, "error": "missing_pin"}), 400
    stored_hash = worker["badge_pin_hash"] or ""
    if not stored_hash:
        return jsonify({"valid": False, "error": "no_pin_set"}), 400
    from werkzeug.security import check_password_hash
    valid = check_password_hash(stored_hash, pin_candidate)
    if not valid:
        cur_entry = _pin_fail_counts.get(worker_id)
        if cur_entry and now - cur_entry[1] < _PIN_LOCKOUT_SECONDS:
            _pin_fail_counts[worker_id] = [cur_entry[0] + 1, cur_entry[1]]
        else:
            _pin_fail_counts[worker_id] = [1, now]
    else:
        _pin_fail_counts.pop(worker_id, None)
    return jsonify({"valid": valid})


@app.put("/api/companies/<company_id>")
@require_auth
@require_roles("superadmin")
def update_company(company_id):
    payload = request.get_json(silent=True) or {}
    db = get_db()
    company = db.execute("SELECT * FROM companies WHERE id = ?", (company_id,)).fetchone()
    if not company:
        return jsonify({"error": "company_not_found"}), 404

    company_name = clean_text_input(payload.get("name", company["name"]), max_len=120)
    company_customer_number = sanitize_customer_number(
        payload.get("customerNumber", company["customer_number"] if "customer_number" in company.keys() else ""),
        max_len=12,
    )
    if not company_customer_number:
        company_customer_number = sanitize_customer_number(company["customer_number"] if "customer_number" in company.keys() else "", max_len=12)
    if not company_customer_number:
        company_customer_number = get_next_customer_number(db)
    company_contact = clean_text_input(payload.get("contact", company["contact"]), max_len=180)
    company_billing_email = clean_text_input(payload.get("billingEmail", company["billing_email"]), max_len=160)
    company_billing_street = clean_text_input(payload.get("billingStreet", company["billing_street"] if "billing_street" in company.keys() else ""), max_len=200)
    company_billing_zip_city = clean_text_input(payload.get("billingZipCity", company["billing_zip_city"] if "billing_zip_city" in company.keys() else ""), max_len=120)
    company_document_email = clean_text_input(payload.get("documentEmail", company["document_email"]), max_len=160)
    if not company_document_email:
        company_document_email = suggest_company_document_email(company_name)
    company_document_email = normalize_email_address(company_document_email)
    company_access_host = clean_text_input((payload.get("accessHost") or payload.get("access_host") or company["access_host"]), max_len=180)
    company_branding_preset = normalize_branding_preset(payload.get("brandingPreset") or payload.get("branding_preset") or company["branding_preset"])
    company_status = clean_text_input(payload.get("status", company["status"]), max_len=32) or company["status"]
    company_trial_ends_at = normalize_company_trial_end(
        payload.get("trialEndsAt", payload.get("trial_ends_at", company["trial_ends_at"] if "trial_ends_at" in company.keys() else ""))
    )
    if company_status == "test" and not company_trial_ends_at:
        company_trial_ends_at = normalize_company_trial_end(company["trial_ends_at"] if "trial_ends_at" in company.keys() else "") or default_company_trial_end_iso()
    if company_status != "test":
        company_trial_ends_at = ""
    company_invoice_email_lang = clean_text_input(payload.get("invoiceEmailLang", company["invoice_email_lang"] if "invoice_email_lang" in company.keys() else "de") or "de", max_len=8)
    if company_invoice_email_lang not in ("de", "en", "fr", "tr", "ar", "es", "it", "pl"):
        company_invoice_email_lang = "de"

    company_keys = company.keys() if hasattr(company, "keys") else []
    if "portalDisplayName" in payload or "portal_display_name" in payload:
        portal_display_name = normalize_portal_display_name(
            payload.get("portalDisplayName", payload.get("portal_display_name", ""))
        )
    else:
        portal_display_name = normalize_portal_display_name(
            company["portal_display_name"] if "portal_display_name" in company_keys else ""
        )
    if "brandingAccentColor" in payload or "branding_accent_color" in payload:
        branding_accent_color = normalize_branding_accent(
            payload.get("brandingAccentColor", payload.get("branding_accent_color", ""))
        )
    else:
        branding_accent_color = normalize_branding_accent(
            company["branding_accent_color"] if "branding_accent_color" in company_keys else ""
        )
    if "brandingLogoData" in payload or "branding_logo_data" in payload:
        branding_logo_data = normalize_branding_logo_data(
            payload.get("brandingLogoData", payload.get("branding_logo_data", ""))
        )
    else:
        branding_logo_data = normalize_branding_logo_data(
            company["branding_logo_data"] if "branding_logo_data" in company_keys else ""
        )
    if "reportTimezone" in payload or "report_timezone" in payload:
        report_timezone = clean_text_input(
            payload.get("reportTimezone", payload.get("report_timezone", "")),
            max_len=64,
        )
        if report_timezone:
            try:
                ZoneInfo(report_timezone)
            except Exception:
                return jsonify({"error": "invalid_timezone", "message": "Ungültige Zeitzone (IANA)."}), 400
    else:
        report_timezone = str(company["report_timezone"] if "report_timezone" in company_keys else "")

    if "operatingSector" in payload or "operating_sector" in payload:
        operating_sector = normalize_operating_sector(
            payload.get("operatingSector", payload.get("operating_sector", ""))
        )
    else:
        operating_sector = normalize_operating_sector(
            company["operating_sector"] if "operating_sector" in company_keys else "construction"
        )

    current_document_email = normalize_email_address(company["document_email"] or "")
    duplicate_customer_no = db.execute(
        "SELECT id, name FROM companies WHERE id != ? AND COALESCE(customer_number, '') = ? LIMIT 1",
        (company_id, company_customer_number),
    ).fetchone()
    if duplicate_customer_no:
        return jsonify({
            "error": "duplicate_customer_number",
            "message": "Diese Kundennummer ist bereits vergeben.",
            "conflictCompanyId": duplicate_customer_no["id"],
            "conflictCompanyName": duplicate_customer_no["name"],
        }), 409

    if company_document_email and company_document_email != current_document_email:
        duplicate_company = db.execute(
            "SELECT id, name FROM companies WHERE deleted_at IS NULL AND id != ? AND lower(document_email) = ? LIMIT 1",
            (company_id, company_document_email),
        ).fetchone()
        if duplicate_company:
            return jsonify({
                "error": "duplicate_document_email",
                "message": "Diese Dokument-E-Mail ist bereits einer anderen Firma zugeordnet.",
                "conflictCompanyId": duplicate_company["id"],
                "conflictCompanyName": duplicate_company["name"],
            }), 409

    db.execute(
        """
        UPDATE companies
        SET name = ?, customer_number = ?, contact = ?, billing_email = ?, billing_street = ?,
            billing_zip_city = ?, document_email = ?, access_host = ?, branding_preset = ?,
            plan = ?, status = ?, trial_ends_at = ?, invoice_email_lang = ?,
            portal_display_name = ?, branding_accent_color = ?, branding_logo_data = ?,
            report_timezone = ?, operating_sector = ?
        WHERE id = ?
        """,
        (
            company_name,
            company_customer_number,
            company_contact,
            company_billing_email,
            company_billing_street,
            company_billing_zip_city,
            company_document_email,
            company_access_host,
            company_branding_preset,
            payload.get("plan", company["plan"]),
            company_status,
            company_trial_ends_at,
            company_invoice_email_lang,
            portal_display_name,
            branding_accent_color,
            branding_logo_data,
            report_timezone,
            operating_sector,
            company_id,
        ),
    )
    rematch_inbox_company_links(db, company_id=company_id)
    db.commit()
    log_audit("company.updated", f"Firma {company_id} aktualisiert", target_type="company", target_id=company_id, company_id=company_id, actor=g.current_user)
    return jsonify({"ok": True})


