@app.post("/api/documents/inbox/<inbox_id>/mark-read")
@require_auth
@require_roles("superadmin", "company-admin", "turnstile")
def mark_inbox_email_read(inbox_id):
    db = get_db()
    row = db.execute("SELECT * FROM email_inbox WHERE id = ?", (inbox_id,)).fetchone()
    if not row:
        return jsonify({"error": "not_found"}), 404
    db.execute("UPDATE email_inbox SET is_read = 1 WHERE id = ?", (inbox_id,))
    db.commit()
    attachments = db.execute(
        "SELECT id, filename, content_type, file_size, assigned_worker_id, assigned_doc_type FROM email_attachments WHERE inbox_id = ?",
        (inbox_id,),
    ).fetchall()
    entry = dict(row)
    entry["is_read"] = 1
    body_text = str(row["body_text"] or "") if "body_text" in row.keys() else ""
    entry["attachments"] = enrich_inbox_attachments_with_pdf_scan(
        db,
        [dict(a) for a in attachments],
        inbox_id,
        subject=str(row["subject"] or ""),
        from_addr=str(row["from_addr"] or ""),
        body_text=body_text,
    )
    if row["matched_company_id"]:
        company = db.execute("SELECT name FROM companies WHERE id = ?", (row["matched_company_id"],)).fetchone()
        if company:
            entry["matched_company_name"] = company["name"]
    return jsonify(entry)


@app.get("/api/integrations/datev/oauth/callback")
def datev_oauth_callback():
    """DATEV OAuth redirect — stores tokens on integration_connections."""
    code = (request.args.get("code") or "").strip()
    state = (request.args.get("state") or "").strip()
    if not code or not state or ":" not in state:
        return jsonify({"error": "invalid_callback"}), 400
    company_id = state.split(":", 1)[0].strip()
    if not company_id:
        return jsonify({"error": "invalid_state"}), 400

    from backend.app.platform.enterprise.datev_client import exchange_datev_code
    from backend.app.platform.enterprise.integration_oauth import merge_oauth_config

    token_result = exchange_datev_code(code)
    if not token_result.get("ok"):
        return jsonify(token_result), 400

    db = get_db()
    tokens = token_result.get("tokens") or {}
    oauth_payload = {
        "access_token": tokens.get("access_token"),
        "refresh_token": tokens.get("refresh_token"),
        "expires_in": tokens.get("expires_in"),
        "token_type": tokens.get("token_type"),
        "scope": tokens.get("scope"),
        "obtained_at": tokens.get("obtained_at"),
    }
    config = merge_oauth_config({}, oauth_payload)
    existing = db.execute(
        "SELECT id FROM integration_connections WHERE company_id = ? AND provider = ?",
        (company_id, "datev"),
    ).fetchone()
    if existing:
        db.execute(
            """
            UPDATE integration_connections
            SET status = 'connected', config_json = ?, updated_at = ?
            WHERE id = ?
            """,
            (json.dumps(config), now_iso(), existing["id"]),
        )
    else:
        iid = f"int-{secrets.token_hex(8)}"
        db.execute(
            """
            INSERT INTO integration_connections (id, company_id, provider, status, config_json, created_at, updated_at)
            VALUES (?, ?, 'datev', 'connected', ?, ?, ?)
            """,
            (iid, company_id, json.dumps(config), now_iso(), now_iso()),
        )
    db.commit()
    return redirect("/index.html#admin?datev=connected")


@app.post("/api/documents/inbox/<inbox_id>/reply")
@require_auth
@require_roles("superadmin", "company-admin")
def reply_to_inbox_email(inbox_id):
    payload = request.get_json(silent=True) or {}
    subject_raw = clean_text_input(payload.get("subject", ""), max_len=240)
    body_raw = clean_text_input(payload.get("body", ""), max_len=8000)
    body_text = str(body_raw or "").strip()
    if not body_text:
        return jsonify({"error": "missing_body"}), 400

    db = get_db()
    current_role = str(g.current_user.get("role") or "")
    if current_role == "superadmin":
        inbox_row = db.execute("SELECT * FROM email_inbox WHERE id = ?", (inbox_id,)).fetchone()
        company_id_for_audit = str(inbox_row["matched_company_id"] or "") if inbox_row else ""
    else:
        company_id = str(g.current_user.get("company_id") or "")
        inbox_row = db.execute(
            """
            SELECT *
            FROM email_inbox
            WHERE id = ?
              AND (
                    matched_company_id = ?
                 OR lower(COALESCE(to_addr, '')) = lower(
                        COALESCE((
                            SELECT document_email
                            FROM companies
                            WHERE id = ?
                            LIMIT 1
                        ), '')
                    )
              )
            LIMIT 1
            """,
            (inbox_id, company_id, company_id),
        ).fetchone()
        company_id_for_audit = company_id

    if not inbox_row:
        return jsonify({"error": "inbox_not_found"}), 404

    recipient = ""
    for _display_name, addr in getaddresses([str(inbox_row["from_addr"] or "")]):
        try:
            recipient = sanitize_optional_email(addr, field_error="invalid_recipient_email")
        except ValueError:
            recipient = ""
        if recipient:
            break
    if not recipient:
        return jsonify({"error": "invalid_recipient_email"}), 400

    settings_row = db.execute(
        """
        SELECT
            smtp_host,
            smtp_port,
            smtp_username,
            smtp_password,
            smtp_sender_email,
            smtp_sender_name,
            smtp_use_tls,
            operator_name,
            platform_name
        FROM settings
        WHERE id = 1
        """
    ).fetchone()
    if not settings_row:
        return jsonify({"error": "settings_missing"}), 500

    original_subject = clean_text_input(inbox_row["subject"] or "", max_len=180)
    subject = subject_raw.strip() or original_subject or "Ihre Nachricht"
    if not subject.lower().startswith("re:"):
        subject = f"Re: {subject}"

    smtp_host = str(settings_row["smtp_host"] or "").strip()
    smtp_port = int(settings_row["smtp_port"] or 587)
    smtp_use_tls = int(settings_row["smtp_use_tls"] or 0) == 1
    smtp_username = str(settings_row["smtp_username"] or "").strip()
    smtp_password = settings_row["smtp_password"] or ""
    smtp_sender = str(settings_row["smtp_sender_email"] or "").strip()
    sender_name = str(
        settings_row["smtp_sender_name"]
        or settings_row["operator_name"]
        or settings_row["platform_name"]
        or "BauPass"
    ).strip()

    original_message_id = clean_text_input(inbox_row["message_id"] or "", max_len=500)
    html_body = "<p style='white-space:pre-wrap;'>" + html.escape(body_text).replace("\n", "<br>") + "</p>"

    smtp_error = ""
    if smtp_host and smtp_sender:
        try:
            msg = EmailMessage()
            msg["Subject"] = subject
            msg["From"] = f"{sender_name} <{smtp_sender}>" if sender_name else smtp_sender
            msg["To"] = recipient
            if original_message_id:
                msg["In-Reply-To"] = original_message_id
                msg["References"] = original_message_id
            msg.set_content(body_text)
            msg.add_alternative(html_body, subtype="html")
            with _smtp_connect(smtp_host, smtp_port, smtp_use_tls) as smtp:
                if smtp_username:
                    smtp.login(smtp_username, smtp_password)
                smtp.send_message(msg)

            log_audit(
                "documents.inbox_reply_sent",
                f"Antwort an {recipient} für Inbox-Mail {inbox_id} gesendet",
                target_type="email_inbox",
                target_id=inbox_id,
                company_id=company_id_for_audit or None,
                actor=g.current_user,
            )
            return jsonify({"ok": True, "provider": "smtp"})
        except Exception as exc:
            smtp_error = str(exc)
            app.logger.warning(f"[DOC-INBOX] SMTP-Antwort fehlgeschlagen ({exc}), versuche API-Fallback")

    sender_for_api = smtp_sender or _normalize_env_value(_resend_key_cache.get("brevo_from_email") or "") or _normalize_env_value(_resend_key_cache.get("from_email") or "")
    if not sender_for_api:
        return jsonify({"error": "sender_not_configured", "smtpError": smtp_error}), 400

    ok, err, provider = _send_via_any_api(
        subject=subject,
        sender_email=sender_for_api,
        sender_name=sender_name,
        recipient=recipient,
        text_body=body_text,
        html_body=html_body,
    )
    if not ok:
        return jsonify({"error": "reply_send_failed", "detail": err, "smtpError": smtp_error}), 500

    log_audit(
        "documents.inbox_reply_sent",
        f"Antwort an {recipient} für Inbox-Mail {inbox_id} via {provider} gesendet",
        target_type="email_inbox",
        target_id=inbox_id,
        company_id=company_id_for_audit or None,
        actor=g.current_user,
    )
    return jsonify({"ok": True, "provider": provider or "api"})


@app.post("/api/documents/inbox/<inbox_id>/attachments/<attachment_id>/assign")
@require_auth
@require_roles("superadmin", "company-admin", "turnstile")
def assign_attachment_to_worker(inbox_id, attachment_id):
    """Hängt einen E-Mail-Anhang an einen Mitarbeiter und speichert die Datei."""
    payload = request.get_json(silent=True) or {}
    worker_id = clean_text_input(payload.get("workerId", ""), max_len=64)
    doc_type = normalize_doc_type(clean_text_input(payload.get("docType", ""), max_len=64))
    notes = clean_text_input(payload.get("notes", ""), max_len=500)

    if not worker_id:
        return jsonify({"error": "missing_worker_id"}), 400
    if doc_type not in ALLOWED_DOC_TYPES:
        return jsonify({"error": "invalid_doc_type", "allowed": sorted(ALLOWED_DOC_TYPES)}), 400

    db = get_db()
    inbox_row = db.execute("SELECT * FROM email_inbox WHERE id = ?", (inbox_id,)).fetchone()
    if not inbox_row:
        return jsonify({"error": "inbox_not_found"}), 404

    att = db.execute(
        "SELECT * FROM email_attachments WHERE id = ? AND inbox_id = ?", (attachment_id, inbox_id)
    ).fetchone()
    if not att:
        return jsonify({"error": "attachment_not_found"}), 404

    worker = db.execute("SELECT * FROM workers WHERE id = ?", (worker_id,)).fetchone()
    if not worker:
        return jsonify({"error": "worker_not_found"}), 404
    if g.current_user["role"] != "superadmin" and worker["company_id"] != g.current_user.get("company_id"):
        return jsonify({"error": "forbidden_worker"}), 403

    # Datei auf Filesystem speichern
    base_upload_root = DOCS_UPLOAD_DIR.resolve()
    worker_doc_dir = (DOCS_UPLOAD_DIR / worker_id).resolve()
    if worker_doc_dir != base_upload_root and base_upload_root not in worker_doc_dir.parents:
        return jsonify({"error": "invalid_storage_path"}), 400
    try:
        worker_doc_dir.mkdir(parents=True, exist_ok=True)
    except Exception as exc:
        return jsonify({"error": "storage_error", "detail": str(exc)}), 500

    ts = utc_now().strftime("%Y%m%d_%H%M%S")
    safe_name = _sanitize_attachment_filename(att["filename"] or "anhang.bin")
    file_path = (worker_doc_dir / f"{doc_type}_{ts}_{safe_name}").resolve()
    if worker_doc_dir not in file_path.parents:
        return jsonify({"error": "invalid_target_path"}), 400

    file_data = att["file_data"]
    if not file_data:
        return jsonify({"error": "attachment_no_data"}), 400

    if isinstance(file_data, memoryview):
        file_data = file_data.tobytes()
    elif isinstance(file_data, bytearray):
        file_data = bytes(file_data)
    elif isinstance(file_data, str):
        file_data = file_data.encode("utf-8", errors="replace")
    else:
        file_data = bytes(file_data)

    if len(file_data) > MAX_IMAP_ATTACHMENT_BYTES:
        return jsonify({"error": "attachment_too_large", "maxBytes": MAX_IMAP_ATTACHMENT_BYTES}), 400

    try:
        file_path.write_bytes(file_data)
    except Exception as exc:
        return jsonify({"error": "write_error", "detail": str(exc)}), 500

    stored_path = _stored_file_path(file_path)

    doc_id = f"doc-{secrets.token_hex(8)}"
    db.execute(
        """INSERT INTO worker_documents
           (id, worker_id, company_id, doc_type, filename, file_path, file_size, source_email_from, source_inbox_id, uploaded_by_user_id, created_at, notes)
           VALUES (?,?,?,?,?,?,?,?,?,?,?,?)""",
        (
            doc_id,
            worker_id,
            worker["company_id"],
            doc_type,
            safe_name,
            stored_path,
            len(file_data),
            inbox_row["from_addr"],
            inbox_id,
            g.current_user["id"],
            now_iso(),
            __import__(
                "backend.app.platform.security.document_fields", fromlist=["maybe_encrypt_field"]
            ).maybe_encrypt_field(notes),
        ),
    )

    # Anhang als zugewiesen markieren
    db.execute(
        "UPDATE email_attachments SET assigned_worker_id = ?, assigned_doc_type = ?, saved_path = ? WHERE id = ?",
        (worker_id, doc_type, stored_path, attachment_id),
    )

    # Wenn alle Anhänge dieser Mail zugewiesen sind → Mail als processed markieren
    unassigned = db.execute(
        "SELECT id FROM email_attachments WHERE inbox_id = ? AND assigned_worker_id IS NULL",
        (inbox_id,),
    ).fetchone()
    if not unassigned:
        db.execute("UPDATE email_inbox SET processed = 1 WHERE id = ?", (inbox_id,))

    unlock_worker_if_documents_valid(db, worker, actor=g.current_user)

    if is_payroll_doc_type(doc_type):
        label = safe_name or "Lohnabrechnung"
        _create_worker_notification(
            db,
            worker_id,
            "payroll_document",
            "Neue Lohnabrechnung",
            f"{label} ist unter Dokumente verfügbar.",
            action_url="documents",
        )

    db.commit()

    if is_payroll_doc_type(doc_type):
        _notify_worker_payroll_document(db, worker_id, safe_name)

    log_audit(
        "worker.document_added",
        f"Dokument '{doc_type}' ({att['filename']}) von {inbox_row['from_addr']} wurde Mitarbeiter {worker['badge_id']} zugewiesen",
        target_type="worker",
        target_id=worker_id,
        company_id=worker["company_id"],
        actor=g.current_user,
    )
    return jsonify({"ok": True, "documentId": doc_id})


